-- ==========================================
-- 易經六十四卦資料表 — Supabase Schema + Seed
-- ==========================================

-- 1. 建立 hexagrams 資料表
CREATE TABLE IF NOT EXISTS hexagrams (
  id SERIAL PRIMARY KEY,
  number INTEGER UNIQUE NOT NULL,
  name_zh TEXT NOT NULL,
  name_en TEXT NOT NULL,
  symbol TEXT NOT NULL,
  upper_trigram TEXT NOT NULL,
  lower_trigram TEXT NOT NULL,
  binary_repr TEXT NOT NULL,
  gua_ci TEXT DEFAULT '',
  tuan_zhuan TEXT DEFAULT '',
  xiang_zhuan TEXT DEFAULT '',
  description TEXT DEFAULT '',
  yao JSONB DEFAULT '[]'
);

-- 2. 建立索引
CREATE INDEX idx_hexagrams_number ON hexagrams(number);
CREATE INDEX idx_hexagrams_binary ON hexagrams(binary_repr);

-- 3. 啟用 RLS 並允許所有人讀取（公開資料）
ALTER TABLE hexagrams ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Hexagrams are publicly readable"
  ON hexagrams FOR SELECT
  USING (true);

-- 4. 插入六十四卦資料
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (1, '乾', 'Qián', '䷀', '乾/天', '乾/天', '111111', '元，亨，利，貞。', '大哉乾元，萬物資始，乃統天。雲行雨施，品物流形。大明始終，六位時成，時乘六龍以御天。乾道變化，各正性命，保合大和，乃利貞。首出庶物，萬國咸寧。', '天行健，君子以自強不息。', '【白話】乾卦。創始、通達、合宜、正固。
【解讀】•《易經》有六十四卦，每一卦都是先畫出卦圖，再標出卦名。卦圖由六爻組成，爻有陰陽之分。所謂六爻，其實是由兩個單卦（各有三爻）所合成。本卦稱 乾卦（下乾上乾），六爻皆陽，陽有剛健之意，象徵原始的生命力，充滿動態的能量。
• 乾卦在六十四卦中，是八純卦之一。所謂純卦，是指上下皆為同一個單卦所組成者。依序出現的有：乾卦（第一卦），坤卦（第二卦），習坎卦（第二十九卦），離卦（第三十卦），震卦（第五十一卦），艮卦（第五十二卦），巽卦（第五十七卦），兌卦（第五十八卦）。
•《易經》有《序卦》，說明六十四卦的排列順序，可供我們理解各卦之參考。譬如，《序卦》開頭就說：“有天地，然後萬物生焉。”意思是以乾卦為天，並以坤卦為地。有天地才能化生萬物。乾代表陽剛勁健的主動力，坤則是承受力，兩者相摩相蕩而變化生出萬物。
“元享利貞”是本卦的卦辭，附在卦名之後，是對本卦所作的基本判斷。“元”，原也，萬物由此創始；“享”，通也，萬物有其共同來源，並且形成一個整體，所以彼此之間通順暢達；“利”，宜也，萬物變遷執行，對一切都有利而和譜，“貞”，正也，由此所展現的萬物，可以堅持自身的途徑，進而恆久不息。', '[{"p":1,"t":"yang","yc":"初九：潛龍，勿用。","xt":"潛龍勿用，陽在下也。","jd":"【白話】初九。龍潛伏著，不要有所作為。\n【解讀】“初九”是本爻的序位。六爻由下而上的序位依序是初、二、三、四、五、上。“九”指陽爻，而“六”指陰爻。陽為奇數，又以動為主，所以取奇數（一、三、五、七、九）之終，表示動之極。陰為偶數，且以靜為主，所以取偶數（二、四、六、八、十）之中，表示靜之極。另一說法，則以揲蓍成卦時，得六、七、八、九四個數字，其中九為老陽（九大於七，七為少陽），六為老陰（陰數如負數，所以，八為少陰）。《易經》用老不用少，故稱九與六。\n“潛龍勿用”是本爻的爻辭，以下各爻皆有爻辭。“龍”是古代傳說中的神奇生物，充滿剛健的活力與變化的勢能，可以“乘2初九位於地之下，猶如在深淵之中，所以稱為“潛龍”，此時不宜有所作為。正如人在年輕時，要努力進德修業，培養實力。\n11乾卦 =風雲而上天”。爻辭多就本爻所處之位，作一客觀的描述，此為筮辭；再論斷其出處進退以及吉凶禍福，此為占驗之辭。以位而言，初、二是地；三、四是人；五、上是天。初九位於地之下，猶如在深淵之中，所以稱為“潛龍”，此時不宜有所作為。\n正如人在年輕時，要努力進德修業，培養實力。"},{"p":2,"t":"yang","yc":"九二：見龍再田，利見大人。","xt":"見龍再田，德施普也。","jd":""},{"p":3,"t":"yang","yc":"九三：君子終日乾乾，夕惕若，厲無咎。","xt":"終日乾乾，反復道也。","jd":""},{"p":4,"t":"yang","yc":"九四：或躍在淵，無咎。","xt":"或躍在淵，進無咎也。","jd":""},{"p":5,"t":"yang","yc":"九五：飛龍在天，利見大人。","xt":"飛龍在天，大人造也。","jd":""},{"p":6,"t":"yang","yc":"上九：亢龍有悔。","xt":"亢龍有悔，盈不可久也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (2, '坤', 'Kūn', '䷁', '坤/地', '坤/地', '000000', '元，亨，利牝馬之貞。 君子有攸往，先迷后得主，利西南得朋，東北喪朋。 安貞，吉。', '至哉坤元，萬物資生，乃順承天。 坤厚載物，德合無疆。 含弘光大，品物咸亨。 牝馬地類，行地無疆，柔順利貞。 君子攸行，先迷失道，后順得常。 西南得朋，乃與類行﹔東北喪朋，乃終有慶。安貞之吉，應地無疆。', '地勢坤，君子以厚德載物。', '', '[{"p":1,"t":"yin","yc":"初六：履霜，堅冰至。","xt":"履霜堅冰，陰始凝也。 馴致其道，至堅冰也。","jd":""},{"p":2,"t":"yin","yc":"六二：直，方，大，不習無不利。","xt":"六二之動，直以方也。 不習無不利，地道光也。","jd":""},{"p":3,"t":"yin","yc":"六三：含章可貞。 或從王事，無成有終。","xt":"含章可貞﹔以時發也。 或從王事，知光大也。","jd":""},{"p":4,"t":"yin","yc":"六四：括囊﹔無咎，無譽。","xt":"括囊無咎，慎不害也。","jd":""},{"p":5,"t":"yin","yc":"六五：黃裳，元吉。","xt":"黃裳元吉，文在中也。","jd":""},{"p":6,"t":"yin","yc":"上六：戰龍於野，其血玄黃。","xt":"戰龍於野，其道窮也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (3, '屯', 'Zhūn', '䷂', '坎/水', '震/雷', '010001', '元，亨，利，貞，勿用，有攸往，利建侯。', '屯，剛柔始交而難生，動乎險中，大亨貞。雷雨之動滿盈，天造草 昧，宜建侯而不寧。', '云，雷，屯﹔君子以經綸。', '', '[{"p":1,"t":"yang","yc":"初九：磐桓﹔利居貞，利建侯。","xt":"雖磐桓，志行正也。 以貴下賤，大得民也。","jd":""},{"p":2,"t":"yin","yc":"六二：屯如邅如，乘馬班如。 匪寇婚媾，女子貞不字，十年乃字。","xt":"六二之難，乘剛也。 十年乃字，反常也。","jd":""},{"p":3,"t":"yin","yc":"六三：既鹿無虞，惟入于林中，君子几不如舍，往吝。","xt":"既鹿無虞，以縱禽也。 君子舍之，往吝窮也。","jd":""},{"p":4,"t":"yin","yc":"六四：乘馬班如，求婚媾，無不利。","xt":"求而往，明也。","jd":""},{"p":5,"t":"yang","yc":"九五：屯其膏，小貞吉，大貞凶。","xt":"屯其膏，施未光也。","jd":""},{"p":6,"t":"yin","yc":"上六：乘馬班如，泣血漣如。","xt":"泣血漣如，何可長也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (4, '蒙', 'Méng', '䷃', '艮/山', '坎/水', '100010', '亨。 匪我求童蒙，童蒙求我。 初噬告，再三瀆，瀆則不告。利貞。', '蒙，山下有險，險而止，蒙。 蒙亨，以亨行時中也。匪我求童蒙，童蒙求我，志應也。 初噬告，以剛中也。再三瀆， 瀆則不告，瀆蒙也。 蒙以養正，聖功也。', '山下出泉，蒙﹔君子以果行育德。', '', '[{"p":1,"t":"yin","yc":"初六：發蒙，利用刑人，用說桎梏，以往吝。","xt":"利用刑人，以正法也。","jd":""},{"p":2,"t":"yang","yc":"九二：包蒙吉﹔納婦吉﹔子克家。","xt":"子克家，剛柔接也。","jd":""},{"p":3,"t":"yin","yc":"六三：勿用娶女﹔見金夫，不有躬，無攸利。","xt":"勿用娶女，行不順也。","jd":""},{"p":4,"t":"yin","yc":"六四：困蒙，吝。","xt":"困蒙之吝，獨遠實也。","jd":""},{"p":5,"t":"yin","yc":"六五：童蒙，吉。","xt":"童蒙之吉，順以巽也。","jd":""},{"p":6,"t":"yang","yc":"上九：擊蒙﹔不利為寇，利御寇。","xt":"利用御寇，上下順也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (5, '需', 'Xū', '䷄', '坎/水', '乾/天', '010111', '有孚，光亨，貞吉。 利涉大川。', '需，須也﹔險在前也。 剛健而不陷，其義不困窮矣。 需有孚，光亨，貞吉。 位乎天位，以正中也。 利涉大川，往有功也。', '云上於天，需﹔君子以飲食宴樂。', '', '[{"p":1,"t":"yang","yc":"初九：需于郊。 利用恆，無咎。","xt":"需于郊，不犯難行也。 利用恆，無咎﹔未失常也。","jd":""},{"p":2,"t":"yang","yc":"九二：需于沙。 小有言，終吉。","xt":"需于沙，衍在中也。 雖小有言，以終吉也。","jd":""},{"p":3,"t":"yang","yc":"九三：需于泥，致寇至。","xt":"需于泥，災在外也。 自我致寇，敬慎不敗也。","jd":""},{"p":4,"t":"yin","yc":"六四：需于血，出自穴。","xt":"需于血，順以聽也。","jd":""},{"p":5,"t":"yang","yc":"九五：需于酒食，貞吉。","xt":"酒食貞吉，以中正也。","jd":""},{"p":6,"t":"yin","yc":"上六：入于穴，有不速之客三人來，敬之終吉。","xt":"不速之客來，敬之終吉。 雖不當位，未大失也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (6, '訟', 'Sòng', '䷅', '乾/天', '坎/水', '111010', '有孚，窒。 惕中吉。 終凶。 利見大人，不利涉大川。', '訟，上剛下險，險而健訟。訟有孚窒，惕中吉，剛來而得中也。終凶﹔訟不可成也。 利見大人﹔尚中正也。不利涉大川﹔入于淵也。', '天與水違行，訟﹔君子以作事謀始。', '', '[{"p":1,"t":"yin","yc":"初六：不永所事，小有言，終吉。","xt":"不永所事，訟不可長也。 雖有小言，其辯明也。","jd":""},{"p":2,"t":"yang","yc":"九二：不克訟，歸而逋，其邑人三百戶，無眚。","xt":"不克訟，歸而逋也。 自下訟上，患至掇也。","jd":""},{"p":3,"t":"yin","yc":"六三：食舊德，貞厲，終吉，或從王事，無成。","xt":"食舊德，從上吉也。","jd":""},{"p":4,"t":"yang","yc":"九四：不克訟，復自命，渝，安貞吉。","xt":"復即命，渝安貞﹔不失也。","jd":""},{"p":5,"t":"yang","yc":"九五：訟元吉。","xt":"訟元吉，以中正也。","jd":""},{"p":6,"t":"yang","yc":"上九：或錫之鞶帶，終朝三褫之。","xt":"以訟受服，亦不足敬也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (7, '師', 'Shī', '䷆', '坤/地', '坎/水', '000010', '貞，丈人，吉無咎。', '師，眾也，貞正也，能以眾正，可以王矣。 剛中而應，行險而順，以此毒天下，而民從之，吉又何咎矣。', '地中有水，師﹔君子以容民畜眾。', '', '[{"p":1,"t":"yin","yc":"初六：師出以律，否臧凶。","xt":"師出以律，失律凶也。","jd":""},{"p":2,"t":"yang","yc":"九二：在師中，吉無咎，王三錫命。","xt":"在師中吉，承天寵也。 王三錫命，懷萬邦也。","jd":""},{"p":3,"t":"yin","yc":"六三：師或輿尸，凶。","xt":"師或輿尸，大無功也。","jd":""},{"p":4,"t":"yin","yc":"六四：師左次，無咎。","xt":"左次無咎，未失常也。","jd":""},{"p":5,"t":"yin","yc":"六五：田有禽，利執言，無咎。長子帥師，弟子輿尸，貞凶。","xt":"長子帥師，以中行也。弟子輿師，使不當也。","jd":""},{"p":6,"t":"yin","yc":"上六：大君有命，開國承家，小人勿用。","xt":"大君有命，以正功也。 小人勿用，必亂邦也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (8, '比', 'Bǐ', '䷇', '坎/水', '坤/地', '010000', '吉。 原筮元永貞，無咎。 不寧方來，后夫凶。', '比，吉也，比，輔也，下順從也。 原筮元永貞，無咎，以剛中也。不寧方來，上下應也。 后夫凶，其道窮也。', '地上有水，比﹔先王以建萬國，親諸侯。', '', '[{"p":1,"t":"yin","yc":"初六：有孚比之，無咎。 有孚盈缶，終來有他，吉。","xt":"比之初六，有他吉也。","jd":""},{"p":2,"t":"yin","yc":"六二：比之自內，貞吉。","xt":"比之自內，不自失也。","jd":""},{"p":3,"t":"yin","yc":"六三：比之匪人。","xt":"比之匪人，不亦傷乎！","jd":""},{"p":4,"t":"yin","yc":"六四：外比之，貞吉。","xt":"外比於賢，以從上也。","jd":""},{"p":5,"t":"yang","yc":"九五：顯比，王用三驅，失前禽。 邑人不誡，吉。","xt":"顯比之吉，位正中也。舍逆取順，失前禽也。 邑人不誡，上使中也。","jd":""},{"p":6,"t":"yin","yc":"上六：比之無首，凶。","xt":"比之無首，無所終也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (9, '小畜', 'Xiǎo Chù', '䷈', '巽/風', '乾/天', '110111', '亨。 密云不雨，自我西郊。', '小畜﹔ 柔得位，而上下應之，曰小畜。 健而巽，剛中而志行，乃亨。 密云不雨，尚往也。 自我西郊，施未行也。', '風行天上，小畜﹔君子以懿文德。', '', '[{"p":1,"t":"yang","yc":"初九：復自道，何其咎，吉。","xt":"復自道，其義吉也。","jd":""},{"p":2,"t":"yang","yc":"九二：牽復，吉。","xt":"牽復在中，亦不自失也。","jd":""},{"p":3,"t":"yang","yc":"九三：輿說輻，夫妻反目。","xt":"夫妻反目，不能正室也。","jd":""},{"p":4,"t":"yin","yc":"六四：有孚，血去惕出，無咎。","xt":"有孚惕出，上合志也。","jd":""},{"p":5,"t":"yang","yc":"九五：有孚攣如，富以其鄰。","xt":"有孚攣如，不獨富也。","jd":""},{"p":6,"t":"yang","yc":"上九：既雨既處，尚德載，婦貞厲。 月几望，君子征凶。","xt":"既雨既處，德積載也。 君子征凶，有所疑也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (10, '履', 'Lǚ', '䷉', '乾/天', '兌/澤', '111011', '履虎尾，不咥人，亨。', '履，柔履剛也。說而應乎乾，是以履虎尾，不咥人，亨。剛中正，履帝位而不疚，光明也。', '上天下澤，履﹔君子以辨上下，安民志。', '', '[{"p":1,"t":"yang","yc":"初九：素履，往無咎。","xt":"素履之往，獨行愿也。","jd":""},{"p":2,"t":"yang","yc":"九二：履道坦坦，幽人貞吉。","xt":"幽人貞吉，中不自亂也。","jd":""},{"p":3,"t":"yin","yc":"六三：眇能視，跛能履，履虎尾，咥人，凶。 武人為于大君。","xt":"眇能視﹔不足以有明也。跛能履﹔不足以與行也。咥人之凶﹔位不當也。 武人為于大君﹔志剛也。","jd":""},{"p":4,"t":"yang","yc":"九四：履虎尾，愬愬終吉。","xt":"愬愬終吉，志行也。","jd":""},{"p":5,"t":"yang","yc":"九五：夬履，貞厲。","xt":"夬履貞厲，位正當也。","jd":""},{"p":6,"t":"yang","yc":"上九：視履考祥，其旋元吉。","xt":"元吉在上，大有慶也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (11, '泰', 'Tài', '䷊', '坤/地', '乾/天', '000111', '小往大來，吉亨。', '泰，小往大來，吉亨。則是天地交，而萬物通也﹔上下交，而其志同也。內陽而外陰，內健而外順，內君子而外小人，君子道長，小人道消也。', '天地交泰，后以財（裁）成天地之道，輔相天地之宜，以左右民。', '', '[{"p":1,"t":"yang","yc":"初九：拔茅茹，以其彙，征吉。","xt":"拔茅征吉，志在外也。","jd":""},{"p":2,"t":"yang","yc":"九二：包荒，用馮河，不遐遺，朋亡，得尚于中行。","xt":"包荒，得尚于中行，以光大也。","jd":""},{"p":3,"t":"yang","yc":"九三：無平不陂，無往不復，艱貞無咎。 勿恤其孚，于食有福。","xt":"無往不復，天地際也。","jd":""},{"p":4,"t":"yin","yc":"六四：翩翩不富，以其鄰，不戒以孚。","xt":"翩翩不富，皆失實也。 不戒以孚，中心愿也。","jd":""},{"p":5,"t":"yin","yc":"六五：帝乙歸妹，以祉元吉。","xt":"以祉元吉，中以行愿也。","jd":""},{"p":6,"t":"yin","yc":"上六：城復于隍，勿用師。 自邑告命，貞吝。","xt":"城復于隍，其命亂也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (12, '否', 'Pǐ', '䷋', '乾/天', '坤/地', '111000', '否之匪人，不利君子貞，大往小來。', '否之匪人，不利君子貞。 大往小來， 則是天地不交，而萬物不通也﹔上下不交，而天下無邦也。內陰而外陽，內柔而外剛，內小人而外君子。 小人道長，君子道消也。', '天地不交，否﹔君子以儉德辟難，不可榮以祿。', '', '[{"p":1,"t":"yin","yc":"初六：拔茅茹，以其彙，貞吉亨。","xt":"拔茅貞吉，志在君也。","jd":""},{"p":2,"t":"yin","yc":"六二：包承。 小人吉，大人否亨。","xt":"大人否亨，不亂群也。","jd":""},{"p":3,"t":"yin","yc":"六三：包羞。","xt":"包羞，位不當也。","jd":""},{"p":4,"t":"yang","yc":"九四：有命無咎，疇離祉。","xt":"有命無咎，志行也。","jd":""},{"p":5,"t":"yang","yc":"九五：休否，大人吉。 其亡其亡，系于苞桑。","xt":"大人之吉，位正當也。","jd":""},{"p":6,"t":"yang","yc":"上九：傾否，先否后喜。","xt":"否終則傾，何可長也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (13, '同人', 'Tóng Rén', '䷌', '乾/天', '離/火', '111101', '同人于野，亨。 利涉大川，利君子貞。', '同人，柔得位得中，而應乎乾，曰同人。 同人曰，同人于野，亨。 利涉大川，乾行也。 文明以健，中正而應，君子正也。 唯君子為能通天下之志。', '天與火，同人﹔君子以類族辨物。', '', '[{"p":1,"t":"yang","yc":"初九：同人于門，無咎。","xt":"出門同人，又誰咎也。","jd":""},{"p":2,"t":"yin","yc":"六二：同人于宗，吝。","xt":"同人于宗，吝道也。","jd":""},{"p":3,"t":"yang","yc":"九三：伏戎于莽，升其高陵，三歲不興。","xt":"伏戎于莽，敵剛也。 三歲不興，安行也。","jd":""},{"p":4,"t":"yang","yc":"九四：乘其墉，弗克攻，吉。","xt":"乘其墉，義弗克也，其吉，則困而反則也。","jd":""},{"p":5,"t":"yang","yc":"九五：同人，先號啕而后笑。 大師克相遇。","xt":"同人之先，以中直也。 大師相遇，言相克也。","jd":""},{"p":6,"t":"yang","yc":"上九：同人于郊，無悔。","xt":"同人于郊，志未得也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (14, '大有', 'Dà Yǒu', '䷍', '離/火', '乾/天', '101111', '元亨。', '大有，柔得尊位，大中而上下應之，曰大有。其德剛健而文明，應乎天而時行，是以元亨。', '火在天上，大有﹔君子以竭惡揚善，順天休命。', '', '[{"p":1,"t":"yang","yc":"初九：無交害，匪咎，艱則無咎。","xt":"大有初九，無交害也。","jd":""},{"p":2,"t":"yang","yc":"九二：大車以載，有攸往，無咎。","xt":"大車以載，積中不敗也。","jd":""},{"p":3,"t":"yang","yc":"九三.公用亨于天子.小人弗克.","xt":"公用亨于天子，小人害也。","jd":""},{"p":4,"t":"yang","yc":"九四：匪其彭，無咎。","xt":"匪其彭，無咎﹔明辨晰也。","jd":""},{"p":5,"t":"yin","yc":"六五：厥孚交如，威如﹔吉。","xt":"厥孚交如，信以發志也。 威如之吉，易而無備也。","jd":""},{"p":6,"t":"yang","yc":"上九：自天佑之，吉無不利。","xt":"大有上吉，自天佑也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (15, '謙', 'Qiān', '䷎', '坤/地', '艮/山', '000100', '亨，君子有終。', '謙，亨，天道下濟而光明，地道卑而上行。天道虧盈而益謙，地道變盈而流謙，鬼神害盈而福謙，人道惡盈而好謙。謙尊而光，卑而不可踰，君子之終也。', '地中有山，謙﹔君子以裒多益寡，稱物平施。', '', '[{"p":1,"t":"yin","yc":"初六：謙謙君子，用涉大川，吉。","xt":"謙謙君子，卑以自牧也。","jd":""},{"p":2,"t":"yin","yc":"六二：鳴謙，貞吉。","xt":"鳴謙貞吉，中心得也。","jd":""},{"p":3,"t":"yang","yc":"九三：勞謙君子，有終吉。","xt":"勞謙君子，萬民服也。","jd":""},{"p":4,"t":"yin","yc":"六四：無不利，撝謙。","xt":"無不利，撝謙﹔不違則也。","jd":""},{"p":5,"t":"yin","yc":"六五：不富，以其鄰，利用侵伐，無不利。","xt":"利用侵伐，征不服也。","jd":""},{"p":6,"t":"yin","yc":"上六：鳴謙，利用行師，征邑國。","xt":"鳴謙，志未得也。 可用行師，征邑國也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (16, '豫', 'Yù', '䷏', '震/雷', '坤/地', '001000', '利建侯,行師。', '豫，剛應而志行，順以動，豫。豫，順以動，故天地如之，而況建侯行師乎？天地以順動，故日月不過，而四時不忒﹔聖人以順動，則刑罰清而民服。 豫之時義大矣哉！', '雷出地奮，豫。 先王以作樂崇德，殷荐之上帝，以配祖考。', '', '[{"p":1,"t":"yin","yc":"初六：鳴豫，凶。","xt":"初六鳴豫，志窮凶也。","jd":""},{"p":2,"t":"yin","yc":"六二：介于石，不終日，貞吉。","xt":"不終日，貞吉﹔以中正也。","jd":""},{"p":3,"t":"yin","yc":"六三：盱豫，悔。 遲有悔。","xt":"盱豫有悔，位不當也。","jd":""},{"p":4,"t":"yang","yc":"九四：由豫，大有得。勿疑。 朋盍簪。","xt":"由豫，大有得﹔志大行也。","jd":""},{"p":5,"t":"yin","yc":"六五：貞疾，恆不死。","xt":"六五貞疾，乘剛也。 恆不死，中未亡也。","jd":""},{"p":6,"t":"yin","yc":"上六：冥豫，成有渝，無咎。","xt":"冥豫在上，何可長也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (17, '隨', 'Suí', '䷐', '兌/澤', '震/雷', '011001', '元亨利貞，無咎。', '隨，剛來而下柔，動而說，隨。大亨貞，無咎，而天下隨時，隨之時義大矣哉！', '澤中有雷，隨﹔君子以□晦入宴息。', '', '[{"p":1,"t":"yang","yc":"初九：官有渝，貞吉。 出門交有功。","xt":"官有渝，從正吉也。 出門交有功，不失也。","jd":""},{"p":2,"t":"yin","yc":"六二：系小子，失丈夫。","xt":"系小子，弗兼與也。","jd":""},{"p":3,"t":"yin","yc":"六三：系丈夫，失小子。 隨有求得，利居貞。","xt":"系丈夫，志舍下也。","jd":""},{"p":4,"t":"yang","yc":"九四：隨有獲，貞凶。有孚在道，以明，何咎。","xt":"隨有獲，其義凶也。 有孚在道，明功也。","jd":""},{"p":5,"t":"yang","yc":"九五：孚于嘉，吉。","xt":"孚于嘉，吉﹔位正中也。","jd":""},{"p":6,"t":"yin","yc":"上六：拘系之，乃從維之。 王用亨于西山。","xt":"拘系之，上窮也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (18, '蠱', 'Gǔ', '䷑', '艮/山', '巽/風', '100110', '元亨，利涉大川。 先甲三日，后甲三日。', '蠱，剛上而柔下，巽而止，蠱。 蠱，元亨，而天下治也。 利涉大川，往有事也。 先甲三日，后甲三日，終則有始，天行也。', '山下有風，蠱﹔君子以振民育德。', '', '[{"p":1,"t":"yin","yc":"初六：干父之蠱，有子，考無咎，厲終吉。","xt":"干父之蠱，意承考也。","jd":""},{"p":2,"t":"yang","yc":"九二：干母之蠱，不可貞。","xt":"干母之蠱，得中道也。","jd":""},{"p":3,"t":"yang","yc":"九三：干父小有晦，無大咎。","xt":"干父之蠱，終無咎也。","jd":""},{"p":4,"t":"yin","yc":"六四：裕父之蠱，往見吝。","xt":"裕父之蠱，往未得也。","jd":""},{"p":5,"t":"yin","yc":"六五：干父之蠱，用譽。","xt":"干父之蠱﹔承以德也。","jd":""},{"p":6,"t":"yang","yc":"上九：不事王侯，高尚其事。","xt":"不事王侯，志可則也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (19, '臨', 'Lín', '䷒', '坤/地', '兌/澤', '000011', '元，亨，利，貞。 至于八月有凶。', '臨，剛浸而長。 說而順，剛中而應，大亨以正，天之道也。 至于八月有凶，消不久也。', '澤上有地，臨﹔ 君子以教思無窮，容保民無疆。', '', '[{"p":1,"t":"yang","yc":"初九：咸臨，貞吉。","xt":"咸臨貞吉，志行正也。","jd":""},{"p":2,"t":"yang","yc":"九二：咸臨，吉無不利。","xt":"咸臨，吉無不利﹔未順命也。","jd":""},{"p":3,"t":"yin","yc":"六三：甘臨，無攸利。 既憂之，無咎。","xt":"甘臨，位不當也。 既憂之，咎不長也。","jd":""},{"p":4,"t":"yin","yc":"六四：至臨，無咎。","xt":"至臨無咎，位當也。","jd":""},{"p":5,"t":"yin","yc":"六五：知臨，大君之宜，吉。","xt":"大君之宜，行中之謂也。","jd":""},{"p":6,"t":"yin","yc":"上六：敦臨，吉無咎。","xt":"敦臨之吉，志在內也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (20, '觀', 'Guān', '䷓', '巽/風', '坤/地', '110000', '盥而不荐，有孚顒若。', '大觀在上，順而巽，中正以觀天下。觀，盥而不荐，有孚□若，下觀而化也。 觀天之神道，而四時不忒， 聖人以神道設教，而天下服矣。', '風行地上，觀﹔先王以省方，觀民設教。', '', '[{"p":1,"t":"yin","yc":"初六：童觀，小人無咎，君子吝。","xt":"初六童觀，小人道也。","jd":""},{"p":2,"t":"yin","yc":"六二：窺觀，利女貞。","xt":"窺觀女貞，亦可丑也。","jd":""},{"p":3,"t":"yin","yc":"六三：觀我生，進退。","xt":"觀我生，進退﹔未失道也。","jd":""},{"p":4,"t":"yin","yc":"六四：觀國之光，利用賓于王。","xt":"觀國之光，尚賓也。","jd":""},{"p":5,"t":"yang","yc":"九五：觀我生，君子無咎。","xt":"觀我生，觀民也。","jd":""},{"p":6,"t":"yang","yc":"上九：觀其生，君子無咎。","xt":"觀其生，志未平也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (21, '噬嗑', 'Shì Kè', '䷔', '離/火', '震/雷', '101001', '亨。 利用獄。', '頤中有物，曰噬嗑，噬嗑而亨。剛柔分，動而明，雷電合而章。柔得中而上行，雖不當位，利用獄也。', '雷電噬嗑﹔先王以明罰敕法。', '', '[{"p":1,"t":"yang","yc":"初九：履校滅趾，無咎。","xt":"履校滅趾，不行也。","jd":""},{"p":2,"t":"yin","yc":"六二：噬膚滅鼻，無咎。","xt":"噬膚滅鼻，乘剛也。","jd":""},{"p":3,"t":"yin","yc":"六三：噬臘肉，遇毒﹔小吝，無咎。","xt":"遇毒，位不當也。","jd":""},{"p":4,"t":"yang","yc":"九四：噬乾胏，得金矢，利艱貞，吉。","xt":"利艱貞吉，未光也。","jd":""},{"p":5,"t":"yin","yc":"六五：噬乾肉，得黃金，貞厲，無咎。","xt":"貞厲無咎，得當也。","jd":""},{"p":6,"t":"yang","yc":"上九：何校滅耳，凶。","xt":"何校滅耳，聰不明也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (22, '賁', 'Bì', '䷕', '艮/山', '離/火', '100101', '亨。 小利有所往。', '賁，亨﹔柔來而文剛，故亨。分剛上而文柔，故小利有攸往。天文也﹔文明以止，人文也。觀乎天文，以察時變﹔觀乎人文，以化成天下。', '山下有火，賁﹔君子以明庶政，無敢折獄。', '', '[{"p":1,"t":"yang","yc":"初九：賁其趾，舍車而徒。","xt":"舍車而徒，義弗乘也。","jd":""},{"p":2,"t":"yin","yc":"六二：賁其須。","xt":"賁其須，與上興也。","jd":""},{"p":3,"t":"yang","yc":"九三：賁如濡如，永貞吉。","xt":"永貞之吉，終莫之陵也。","jd":""},{"p":4,"t":"yin","yc":"六四：賁如皤如，白馬翰如，匪寇婚媾。","xt":"六四，當位疑也。 匪寇婚媾，終無尤也。","jd":""},{"p":5,"t":"yin","yc":"六五：賁于丘園，束帛戔戔，吝，終吉。","xt":"六五之吉，有喜也。","jd":""},{"p":6,"t":"yang","yc":"上九：白賁，無咎。","xt":"白賁無咎，上得志也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (23, '剝', 'Bō', '䷖', '艮/山', '坤/地', '100000', '不利有攸往。', '剝，剝也，柔變剛也。 不利有攸往，小人長也。 順而止之，觀象也。 君子尚消息盈虛，天行也。', '山附地上，剝﹔上以厚下，安宅。', '', '[{"p":1,"t":"yin","yc":"初六：剝床以足，蔑貞凶。","xt":"剝床以足，以滅下也。","jd":""},{"p":2,"t":"yin","yc":"六二：剝床以辨，蔑貞凶。","xt":"剝床以辨，未有與也。","jd":""},{"p":3,"t":"yin","yc":"六三：剝之，無咎。","xt":"剝之無咎，失上下也。","jd":""},{"p":4,"t":"yin","yc":"六四：剝床以膚，凶。","xt":"剝床以膚，切近災也。","jd":""},{"p":5,"t":"yin","yc":"六五：貫魚，以宮人寵，無不利。","xt":"以宮人寵，終無尤也。","jd":""},{"p":6,"t":"yang","yc":"上九：碩果不食，君子得輿，小人剝廬。","xt":"君子得輿，民所載也。 小人剝廬，終不可用也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (24, '復', 'Fù', '䷗', '坤/地', '震/雷', '000001', '亨。 出入無疾，朋來無咎。 反復其道，七日來復，利有攸往。', '復亨﹔剛反，動而以順行，是以出入無疾，朋來無咎。 反復其道，七日來復，天行也。 利有攸往，剛長也。 復其見天地之心乎？', '雷在地中，復﹔先王以至日閉關，商旅不行，后不省方。', '', '[{"p":1,"t":"yang","yc":"初九：不復遠，無只悔，元吉。","xt":"不遠之復，以修身也。","jd":""},{"p":2,"t":"yin","yc":"六二：休復，吉。","xt":"休復之吉，以下仁也。","jd":""},{"p":3,"t":"yin","yc":"六三：頻復，厲無咎。","xt":"頻復之厲，義無咎也。","jd":""},{"p":4,"t":"yin","yc":"六四：中行獨復。","xt":"中行獨復，以從道也。","jd":""},{"p":5,"t":"yin","yc":"六五：敦復，無悔。","xt":"敦復無悔，中以自考也。","jd":""},{"p":6,"t":"yin","yc":"上六：迷復，凶，有災眚。用行師，終有大敗，以其國君，凶﹔至于十年，不克征。","xt":"迷復之凶，反君道也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (25, '無妄', 'Wú Wàng', '䷘', '乾/天', '震/雷', '111001', '元，亨，利，貞。 其匪正有眚，不利有攸往。', '無妄，剛自外來，而為主於內。動而健，剛中而應，大亨以正，天之命也。 其匪正有眚，不利有攸往。無妄之往，何之矣？ 天命不佑，行矣哉？', '天下雷行，物與無妄﹔先王以茂對時，育萬物。', '', '[{"p":1,"t":"yang","yc":"初九：無妄，往吉。","xt":"無妄之往，得志也。","jd":""},{"p":2,"t":"yin","yc":"六二：不耕獲，不菑畬，則利有攸往。","xt":"不耕獲，未富也。","jd":""},{"p":3,"t":"yin","yc":"六三：無妄之災，或系之牛，行人之得，邑人之災。","xt":"行人得牛，邑人災也。","jd":""},{"p":4,"t":"yang","yc":"九四：可貞，無咎。","xt":"可貞無咎，固有之也。","jd":""},{"p":5,"t":"yang","yc":"九五：無妄之疾，勿藥有喜。","xt":"無妄之藥，不可試也。","jd":""},{"p":6,"t":"yang","yc":"上九：無妄，行有眚，無攸利。","xt":"無妄之行，窮之災也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (26, '大畜', 'Dà Chù', '䷙', '艮/山', '乾/天', '100111', '利貞，不家食吉，利涉大川。', '大畜，剛健篤實輝光，日新其德，剛上而尚賢。 能止健，大正也。不家食吉，養賢也。 利涉大川，應乎天也。', '天在山中，大畜﹔君子以多識前言往行，以畜其德。', '大畜。利貞。不家食，吉。利涉大川。
【白話】大畜卦。適宜正固。不吃家裡的飯，吉祥。適宜渡過大河。
【解讀】• 大畜卦是下乾上艮，亦即“山天大畜”。《序卦》說：“有無妄然後可畜，故受之以大畜。”不虛妄則是真誠而實在，由此培養內涵，然後可以大有積蓄。
• 積蓄德行與學識之後，成為賢人，將會受到國家禮遇，不必在家裡吃閒飯。這表示政治上軌道，所以說“吉”。面對艱難險阻，也可以大步前行，是為“利涉大川”。
《彖》曰：大畜。剛健篤實輝光，日新其德，剛上而尚賢。能止健，大正也。不家食吉，養賢也。利涉大川，應乎天也。
【白話】《彖傳》說：大畜卦。剛強勁健厚重實在而輝映光彩，其德日日更新，它的作風是要讓剛強者居上位，由此推崇賢人。能夠止住勁健，是因為充滿正固的力量。不吃家裡的飯而吉祥，是因為國家在培養賢人。適宜渡過大河，則是為了配合天的法則。
【解讀】• 大畜卦下乾上艮，艮為山，乾為天。天行剛健而山處厚實；外靜而內動，在大的積蓄中，還須不斷推陳出新。由“剛上”一語可知本卦由大壯卦（䷡，第三十四卦）變成，亦即九四成為上九，陽爻居最高位，是為“尚賢”，由此而來的“養賢”，則是“不家食”。
• “能止健”，內動強勁（乾），而外有山止（艮），必定具有極大的正固力量，進而可以克服險阻，亦即“利涉大川”。
《象》曰：天在山中，大畜。君子以多識前言往行，以畜其德。
【白話】《象傳》說：“天”處在“山”裡面，這就是大畜卦。君子由此領悟，要廣泛學習並記得古人的言行，以培養自己的深厚道德。
【解讀】• 大畜卦下乾上艮，其象即是“天在山中”。天為至大而無所不覆，現在卻被山所包容，可見其蓄積之大。
• “識”為由學習而記住。“畜德”表示道德也須蘊蓄以成其厚。
向古人學習，是一個好辦法。', '[{"p":1,"t":"yang","yc":"初九：有厲利已。","xt":"有厲利已，不犯災也。","jd":"初九。有歷，利已。\n《象》日：有厲利已，不犯災也。\n【白話】初九。有危險，適宜停止。\n《象傳》說：有危險而適宜停止，是為了不要招惹災禍。\n【解讀】• 大畜卦以積蓄涵養為原則。初九陽剛易動，又有六四正應，有躍躍欲試之象，所以要警惕它“有厲”。\n•“利已”，“已”是停止，停止是為了“不犯災”，“犯”是干犯、招惹。在此卦中，上下正應的陽爻，都以“止”為宜。"},{"p":2,"t":"yang","yc":"九二：輿說輻。","xt":"輿說輻，中無尤也。","jd":"九二。與說輹。\n《象》曰：輿說輹，中無尤也。\n【白話】九二。車廂脫離了車軸。\n《象傳》說：車廂脫離了車軸，是因為居中而沒有過失。\n【解讀】• “說”同“脫”，“復”是連線車廂與車軸的零件（古稱“伏兔”）。\n九二與六五正應，也是想行動而不可得。由象上看，九二在互震（九三、六四、六五）之下，與震分離，震行，又有車廂之象，但與九二脫了節。\n• 九二居下卦中位，言行適中，現在因“輿說複”而行不得，所以“無尤”。"},{"p":3,"t":"yang","yc":"九三：良馬逐，利艱貞。 曰閑輿衛，利有攸往。","xt":"利有攸往，上合志也。","jd":"九三。良馬逐，利艱貞。日閒與衛，利有攸往。\n《象》曰：利有攸往，上合志也。\n【白話】九三。駿馬奔馳，適宜在艱難中正固。每天練習駕車與防衛，適宜有所前往。\n《象傳》說：適宜有所前往，是因為與上位者心意相合。\n【解讀】• 九三在下卦乾中，乾為馬；又在互震（九三、六四、六五）中，震為行；合之則為“良馬逐”。不過，它面臨艮卦，艮為止，表示有阻力，所以“利艱貞”。\n• “閒”為嫻熟、練習，“輿”指駕車，“衛”指防衛，都是古代作戰必備的能力。如果具備這些條件，才可以“利有攸往”。\n•對九三而言，雖與上九無應，但兩者皆為陽爻，在本卦中，可謂心意相合，可以往前邁進。"},{"p":4,"t":"yin","yc":"六四：童牛之牿，元吉。","xt":"六四元吉，有喜也。","jd":"六四。童牛之牿，元吉。\n《象》曰：六四元吉，有喜也。\n【白話】六四。小牛在角上綁了橫木，最為吉祥。\n《象傳》說：六四最為吉祥，是因為有了喜悅之事。\n【解讀】• “牿”是綁在牛角上的橫木，使牛角無法刺傷人。這是古人畜養小牛的方式。如此一來，小牛由野而馴，成為極有價值的家畜，可以耕田也可以拖車，確實“元吉”。程頤說：“人之惡止於初則易，既盛而後禁，則扦格而難勝。”小惡之人，導之可使為善。\n• 大畜卦是四陽畜二陰，在六四與六五，分別談及牛與豬，所畜皆為對人類有利之生物。六四在互兌（九二、九三、六四）中，兌為悅，所以“有喜”。"},{"p":5,"t":"yin","yc":"六五：豶豕之牙，吉。","xt":"六五之吉，有慶也。","jd":"六五。豶豕之牙，吉。\n《象》日：六五之吉，有慶也。\n【白話】六五。閹豬口中的牙，吉祥。\n《象傳》說：六五的吉祥，是因為有了喜慶之事。\n【解讀】• “豶”是去勢或閹過的豬，“豕”是豬。野豬的獠牙是傷害人的利器，“豶豕”已無野性，它的牙對人就沒有威脅了，豕反而成為人類食物的來源，所以說“吉”。\n• 六五居尊位，又有九二正應，現在把天下人引以為患的野豬馴成了家畜，自然“有慶”。“豶豕”之喻，是要從根本上化解不當慾望的來源，而最好的方法則是修明政教，上行下效，大家一起蓄積德行。"},{"p":6,"t":"yang","yc":"上九：何天之衢，亨。","xt":"何天之衢，道大行也。","jd":"上九。何天之衢，亨。\n《象》曰：何天之衢，道大行也。\n【白話】上九。位處上天所賜的通路，通達。\n《象傳》說：位處上天所賜的通路，正道可以充分實現了。\n【解讀】• “何”為荷，為擔負、承受、獲得之意。“衢” 為交通要道。上九居天位，在全卦最上，獲得全卦的支援；上九又在互震（九三、六四、六五）之上，震為大途；合而觀之，則是“何天之衢”，亦即位居上天所展示的大路上。\n• 大畜卦所蓄積的條件，在上九發揮了作用，使它可以無往不利，充分實現正道。"}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (27, '頤', 'Yí', '䷚', '艮/山', '震/雷', '100001', '貞吉。 觀頤，自求口實。', '頤貞吉，養正則吉也。 觀頤，觀其所養也﹔ 自求口實，觀其自養也。 天地養萬物，聖人養賢，以及萬民﹔頤之時義大矣哉！', '山下有雷，頤﹔君子以慎言語，節飲食。', '', '[{"p":1,"t":"yang","yc":"初九：舍爾靈龜，觀我朵頤，凶。","xt":"觀我朵頤，亦不足貴也。","jd":""},{"p":2,"t":"yin","yc":"六二：顛頤，拂經，于丘頤，征凶。","xt":"六二征凶，行失類也。","jd":""},{"p":3,"t":"yin","yc":"六三：拂頤，貞凶，十年勿用，無攸利。","xt":"十年勿用，道大悖也。","jd":""},{"p":4,"t":"yin","yc":"六四：顛頤吉，虎視眈眈，其欲逐逐，無咎。","xt":"顛頤之吉，上施光也。","jd":""},{"p":5,"t":"yin","yc":"六五：拂經，居貞吉，不可涉大川。","xt":"居貞之吉，順以從上也。","jd":""},{"p":6,"t":"yang","yc":"上九：由頤，厲吉，利涉大川。","xt":"由頤厲吉，大有慶也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (28, '大過', 'Dà Guò', '䷛', '兌/澤', '巽/風', '011110', '棟橈，利有攸往，亨。', '大過，大者過也。 棟橈，本末弱也。 剛過而中，巽而說行，利有攸往，乃亨。 大過之時義大矣哉！', '澤滅木，大過﹔君子以獨立不懼，遯世無悶。', '', '[{"p":1,"t":"yin","yc":"初六：藉用白茅，無咎。","xt":"藉用白茅，柔在下也。","jd":""},{"p":2,"t":"yang","yc":"九二：枯楊生稊，老夫得其女妻，無不利。","xt":"老夫女妻，過以相與也。","jd":""},{"p":3,"t":"yang","yc":"九三：棟橈，凶。","xt":"棟橈之凶，不可以有輔也。","jd":""},{"p":4,"t":"yang","yc":"九四：棟隆，吉﹔有它吝。","xt":"棟隆之吉，不橈乎下也。","jd":""},{"p":5,"t":"yang","yc":"九五：枯楊生華，老婦得士夫，無咎無譽。","xt":"枯楊生華，何可久也。 老婦士夫，亦可丑也。","jd":""},{"p":6,"t":"yin","yc":"上六：過涉滅頂，凶，無咎。","xt":"過涉之凶，不可咎也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (29, '坎', 'Kǎn', '䷜', '坎/水', '坎/水', '010010', '習坎，有孚，維心亨，行有尚。', '習坎，重險也。 水流而不盈，行險而不失其信。 維心亨，乃以剛中也。 行有尚，往有功也。 天險不可升也，地險山川丘陵也，王公設險以守其國，坎之時用大矣哉！', '水洊至，習坎﹔君子以常德行，習教事。', '', '[{"p":1,"t":"yin","yc":"初六：習坎，入于坎窞，凶。","xt":"習坎入坎，失道凶也。","jd":""},{"p":2,"t":"yang","yc":"九二：坎有險，求小得。","xt":"求小得，未出中也。","jd":""},{"p":3,"t":"yin","yc":"六三：來之坎坎，險且枕，入于坎窞，勿用。","xt":"來之坎坎，終無功也。","jd":""},{"p":4,"t":"yin","yc":"六四：樽酒簋貳，用缶，納約自牖，終無咎。","xt":"樽酒簋貳，剛柔際也。","jd":""},{"p":5,"t":"yang","yc":"九五：坎不盈，只既平，無咎。","xt":"坎不盈，中未大也。","jd":""},{"p":6,"t":"yin","yc":"上六：係用徽纆，置于叢棘，三歲不得，凶。","xt":"上六失道，凶三歲也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (30, '離', 'Lí', '䷝', '離/火', '離/火', '101101', '利貞，亨。 畜牝牛，吉。', '離，麗也﹔日月麗乎天，百谷草木麗乎土，重明以麗乎正，乃化成天下。 柔麗乎中正，故亨﹔是以畜牝牛吉也。', '明兩作離，大人以繼明照于四方。', '', '[{"p":1,"t":"yang","yc":"初九：履錯然，敬之無咎。","xt":"履錯之敬，以辟咎也。","jd":""},{"p":2,"t":"yin","yc":"六二：黃離，元吉。","xt":"黃離元吉，得中道也。","jd":""},{"p":3,"t":"yang","yc":"九三：日昃之離，不鼓缶而歌，則大耋之嗟，凶。","xt":"日昃之離，何可久也。","jd":""},{"p":4,"t":"yang","yc":"九四：突如其來如，焚如，死如，棄如。","xt":"突如其來如，無所容也。","jd":""},{"p":5,"t":"yin","yc":"六五：出涕沱若，戚嗟若，吉。","xt":"六五之吉，離王公也。","jd":""},{"p":6,"t":"yang","yc":"上九：王用出征，有嘉折首，獲其匪丑，無咎。","xt":"王用出征，以正邦也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (31, '咸', 'Xián', '䷞', '兌/澤', '艮/山', '011100', '亨，利貞，取女吉。', '咸，感也。柔上而剛下，二氣感應以相與，止而說，男下女，是以亨利貞，取女吉也。天地感而萬物化生，聖人感人心而天下和平﹔觀其所感，而天地萬物之情可見矣！', '山上有澤，咸﹔君子以虛受人。', '', '[{"p":1,"t":"yin","yc":"初六：咸其拇。","xt":"咸其拇，志在外也。","jd":""},{"p":2,"t":"yin","yc":"六二：咸其腓，凶，居吉。","xt":"雖凶，居吉，順不害也。","jd":""},{"p":3,"t":"yang","yc":"九三：咸其股，執其隨，往吝。","xt":"咸其股，亦不處也。 志在隨人，所執下也。","jd":""},{"p":4,"t":"yang","yc":"九四：貞吉悔亡，憧憧往來，朋從爾思。","xt":"貞吉悔亡，未感害也。 憧憧往來，未光大也。","jd":""},{"p":5,"t":"yang","yc":"九五：咸其脢，無悔。","xt":"咸其脢，志末也。","jd":""},{"p":6,"t":"yin","yc":"上六：咸其輔，頰，舌。","xt":"咸其輔，頰，舌，滕脢說也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (32, '恆', 'Héng', '䷟', '震/雷', '巽/風', '001110', '亨，無咎，利貞，利有攸往。', '恆，久也。 剛上而柔下，雷風相與，巽而動，剛柔皆應，恆。 恆亨無咎，利貞﹔ 久於其道也，天地之道，恆久而不已也。 利有攸往，終則有始也。日月得天，而能久照，四時變化，而能久成，聖人久於其道，而天下化成﹔觀其所恆，而天地萬物之情可見矣！', '雷風，恆﹔君子以立不易方。', '', '[{"p":1,"t":"yin","yc":"初六：浚恆，貞凶，無攸利。","xt":"浚恆之凶，始求深也。","jd":""},{"p":2,"t":"yang","yc":"九二：悔亡。","xt":"九二悔亡，能久中也。","jd":""},{"p":3,"t":"yang","yc":"九三：不恆其德，或承之羞，貞吝。","xt":"不恆其德，無所容也。","jd":""},{"p":4,"t":"yang","yc":"九四：田無禽。","xt":"久非其位，安得禽也。","jd":""},{"p":5,"t":"yin","yc":"六五：恆其德，貞，婦人吉，夫子凶。","xt":"婦人貞吉，從一而終也。 夫子制義，從婦凶也。","jd":""},{"p":6,"t":"yin","yc":"上六：振恆，凶。","xt":"振恆在上，大無功也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (33, '遯', 'Dùn', '䷠', '乾/天', '艮/山', '111100', '亨，小利貞。', '遯亨，遯而亨也。 剛當位而應，與時行也。 小利貞，浸而長也。遯之時義大矣哉！', '天下有山，遯﹔君子以遠小人，不惡而嚴。', '', '[{"p":1,"t":"yin","yc":"初六：遯尾，厲，勿用有攸往。","xt":"遯尾之厲，不往何災也。","jd":""},{"p":2,"t":"yin","yc":"六二：執之用黃牛之革，莫之勝說。","xt":"執用黃牛，固志也。","jd":""},{"p":3,"t":"yang","yc":"九三：系遯，有疾厲，畜臣妾吉。","xt":"系遯之厲，有疾憊也。 畜臣妾吉，不可大事也。","jd":""},{"p":4,"t":"yang","yc":"九四：好遯君子吉，小人否。","xt":"君子好遯，小人否也。","jd":""},{"p":5,"t":"yang","yc":"九五：嘉遯，貞吉。","xt":"嘉遯貞吉，以正志也。","jd":""},{"p":6,"t":"yang","yc":"上九：肥遯，無不利。","xt":"肥遯，無不利﹔無所疑也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (34, '大壯', 'Dà Zhuàng', '䷡', '震/雷', '乾/天', '001111', '利貞。', '大壯，大者壯也。 剛以動，故壯。 大壯利貞﹔大者正也。正大而天地之情可見矣！', '雷在天上，大壯﹔君子以非禮勿履。', '', '[{"p":1,"t":"yang","yc":"初九：壯于趾，征凶，有孚。","xt":"壯于趾，其孚窮也。","jd":""},{"p":2,"t":"yang","yc":"九二：貞吉。","xt":"九二貞吉，以中也。","jd":""},{"p":3,"t":"yang","yc":"九三：小人用壯，君子用罔，貞厲。 羝羊觸藩，羸其角。","xt":"小人用壯，君子罔也。","jd":""},{"p":4,"t":"yang","yc":"九四：貞吉悔亡，藩決不羸，壯于大輿之輹。","xt":"藩決不羸，尚往也。","jd":""},{"p":5,"t":"yin","yc":"六五：喪羊于易，無悔。","xt":"喪羊于易，位不當也。","jd":""},{"p":6,"t":"yin","yc":"上六：羝羊觸藩，不能退，不能遂，無攸利，艱則吉。","xt":"不能退，不能遂，不祥也。 艱則吉，咎不長也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (35, '晉', 'Jìn', '䷢', '離/火', '坤/地', '101000', '康侯用錫馬蕃庶，晝日三接。', '晉，進也。 明出地上，順而麗乎大明，柔進而上行。 是以康侯用錫馬蕃庶，晝日三接也。', '明出地上，晉﹔君子以自昭明德。', '', '[{"p":1,"t":"yin","yc":"初六：晉如，摧如，貞吉。 罔孚，裕無咎。","xt":"晉如，摧如﹔獨行正也。 裕無咎﹔未受命也。","jd":""},{"p":2,"t":"yin","yc":"六二：晉如，愁如，貞吉。 受茲介福，于其王母。","xt":"受之介福，以中正也。","jd":""},{"p":3,"t":"yin","yc":"六三：眾允，悔亡。","xt":"眾允之，志上行也。","jd":""},{"p":4,"t":"yang","yc":"九四：晉如碩鼠，貞厲。","xt":"碩鼠貞厲，位不當也。","jd":""},{"p":5,"t":"yin","yc":"六五：悔亡，失得勿恤，往吉無不利。","xt":"失得勿恤，往有慶也。","jd":""},{"p":6,"t":"yang","yc":"上九：晉其角，維用伐邑，厲吉無咎，貞吝。","xt":"維用伐邑，道未光也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (36, '明夷', 'Míng Yí', '䷣', '坤/地', '離/火', '000101', '利艱貞。', '明入地中，明夷。 內文明而外柔順，以蒙大難，文王以之。 利艱貞，晦其明也，內難而能正其志，箕子以之。', '明入地中，明夷﹔君子以蒞眾，用晦而明。', '', '[{"p":1,"t":"yang","yc":"初九：明夷于飛，垂其翼。 君子于行，三日不食， 有攸往，主人有言。","xt":"君子于行，義不食也。","jd":""},{"p":2,"t":"yin","yc":"六二：明夷，夷于左股，用拯馬壯，吉。","xt":"六二之吉，順以則也。","jd":""},{"p":3,"t":"yang","yc":"九三：明夷于南狩，得其大首，不可疾貞。","xt":"南狩之志，乃大得也。","jd":""},{"p":4,"t":"yin","yc":"六四：入于左腹，獲明夷之心，出于門庭。","xt":"入于左腹，獲心意也。","jd":""},{"p":5,"t":"yin","yc":"六五：箕子之明夷，利貞。","xt":"箕子之貞，明不可息也。","jd":""},{"p":6,"t":"yin","yc":"上六：不明晦，初登于天，后入于地。","xt":"初登于天，照四國也。 后入于地，失則也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (37, '家人', 'Jiā Rén', '䷤', '巽/風', '離/火', '110101', '利女貞。', '家人，女正位乎內，男正位乎外，男女正，天地之大義也。家人有嚴君焉，父母之謂也。父父，子子，兄兄，弟弟，夫夫，婦婦，而家道正﹔正家而天下定矣。', '風自火出，家人﹔君子以言有物，而行有恆。', '', '[{"p":1,"t":"yang","yc":"初九：閑有家，悔亡。","xt":"閑有家，志未變也。","jd":""},{"p":2,"t":"yin","yc":"六二：無攸遂，在中饋，貞吉。","xt":"六二之吉，順以巽也。","jd":""},{"p":3,"t":"yang","yc":"九三：家人嗃嗃，悔厲吉﹔婦子嘻嘻，終吝。","xt":"家人嗃嗃，未失也﹔婦子嘻嘻，失家節也。","jd":""},{"p":4,"t":"yin","yc":"六四：富家，大吉。","xt":"富家大吉，順在位也。","jd":""},{"p":5,"t":"yang","yc":"九五：王假有家，勿恤吉。","xt":"王假有家，交相愛也。","jd":""},{"p":6,"t":"yang","yc":"上九：有孚威如，終吉。","xt":"威如之吉，反身之謂也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (38, '睽', 'Kuí', '䷥', '離/火', '兌/澤', '101011', '小事吉。', '睽，火動而上，澤動而下﹔ 二女同居，其志不同行﹔說而麗乎明，柔進而上行，得中而應乎剛﹔是以小事吉。 天地睽，而其事同也﹔男女睽，而其志通也﹔萬物睽，而其事類也﹔睽之時用大矣哉！', '上火下澤，睽﹔君子以同而異。', '', '[{"p":1,"t":"yang","yc":"初九：悔亡，喪馬勿逐，自復﹔見惡人無咎。","xt":"見惡人，以辟咎也。","jd":""},{"p":2,"t":"yang","yc":"九二：遇主于巷，無咎。","xt":"遇主于巷，未失道也。","jd":""},{"p":3,"t":"yin","yc":"六三：見輿曳，其牛掣，其人天且劓，無初有終。","xt":"見輿曳，位不當也。 無初有終，遇剛也。","jd":""},{"p":4,"t":"yang","yc":"九四：睽孤，遇元夫，交孚，厲無咎。","xt":"交孚無咎，志行也。","jd":""},{"p":5,"t":"yin","yc":"六五：悔亡，厥宗噬膚，往何咎。","xt":"厥宗噬膚，往有慶也。","jd":""},{"p":6,"t":"yang","yc":"上九：睽孤， 見豕負涂，載鬼一車， 先張之弧，后說之弧，匪寇婚媾，往遇雨則吉。","xt":"遇雨之吉，群疑亡也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (39, '蹇', 'Jiǎn', '䷦', '坎/水', '艮/山', '010100', '利西南，不利東北﹔利見大人，貞吉。', '蹇，難也，險在前也。 見險而能止，知矣哉！蹇利西南， 往得中也﹔不利東北，其道窮也。 利見大人，往有功也。 當位貞吉，以正邦也。 蹇之時用大矣哉！', '山上有水，蹇﹔君子以反身修德。', '', '[{"p":1,"t":"yin","yc":"初六：往蹇，來譽。","xt":"往蹇來譽，宜待也。","jd":""},{"p":2,"t":"yin","yc":"六二：王臣蹇蹇，匪躬之故。","xt":"王臣蹇蹇，終無尤也。","jd":""},{"p":3,"t":"yang","yc":"九三：往蹇來反。","xt":"往蹇來反，內喜之也。","jd":""},{"p":4,"t":"yin","yc":"六四：往蹇來連。","xt":"往蹇來連，當位實也。","jd":""},{"p":5,"t":"yang","yc":"九五：大蹇朋來。","xt":"大蹇朋來，以中節也。","jd":""},{"p":6,"t":"yin","yc":"上六：往蹇來碩，吉﹔利見大人。","xt":"往蹇來碩，志在內也。 利見大人，以從貴也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (40, '解', 'Xiè', '䷧', '震/雷', '坎/水', '001010', '利西南，無所往，其來復吉。 有攸往，夙吉。', '解，險以動，動而免乎險，解。 解利西南，往得眾也。其來復吉， 乃得中也。有攸往夙吉，往有功也。 天地解，而雷雨作，雷雨作，而百果草木皆甲坼，解之時義大矣哉！', '雷雨作，解﹔君子以赦過宥罪。', '', '[{"p":1,"t":"yin","yc":"初六：無咎。","xt":"剛柔之際，義無咎也。","jd":""},{"p":2,"t":"yang","yc":"九二：田獲三狐，得黃矢，貞吉。","xt":"九二貞吉，得中道也。","jd":""},{"p":3,"t":"yin","yc":"六三：負且乘，致寇至，貞吝。","xt":"負且乘，亦可丑也，自我致戎，又誰咎也。","jd":""},{"p":4,"t":"yang","yc":"九四：解而拇，朋至斯孚。","xt":"解而拇，未當位也。","jd":""},{"p":5,"t":"yin","yc":"六五：君子維有解，吉﹔有孚于小人。","xt":"君子有解，小人退也。","jd":""},{"p":6,"t":"yin","yc":"上六：公用射隼，于高墉之上，獲之，無不利。","xt":"公用射隼，以解悖也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (41, '損', 'Sǔn', '䷨', '艮/山', '兌/澤', '100011', '有孚，元吉，無咎，可貞，利有攸往？  曷之用，二簋可用享。', '損，損下益上，其道上行。損而有孚，元吉，無咎，可貞，利有攸往。 曷之用？ 二簋可用享﹔二簋應有時。損剛益柔有時，損益盈虛，與時偕行。', '山下有澤，損﹔君子以懲忿窒欲。', '', '[{"p":1,"t":"yang","yc":"初九：已事遄往，無咎，酌損之。","xt":"已事遄往，尚合志也。","jd":""},{"p":2,"t":"yang","yc":"九二：利貞，征凶，弗損益之。","xt":"九二利貞，中以為志也。","jd":""},{"p":3,"t":"yin","yc":"六三：三人行，則損一人﹔一人行，則得其友。","xt":"一人行，三則疑也。","jd":""},{"p":4,"t":"yin","yc":"六四：損其疾，使遄有喜，無咎。","xt":"損其疾，亦可喜也。","jd":""},{"p":5,"t":"yin","yc":"六五：或益之，十朋之龜弗克違，元吉。","xt":"六五元吉，自上佑也。","jd":""},{"p":6,"t":"yang","yc":"上九：弗損益之，無咎，貞吉，利有攸往，得臣無家。","xt":"弗損益之，大得志也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (42, '益', 'Yì', '䷩', '巽/風', '震/雷', '110001', '利有攸往，利涉大川。', '益，損上益下，民說無疆，自上下下，其道大光。利有攸往，中正有慶。 利涉大川，木道乃行。 益動而巽，日進無疆。 天施地生，其益無方。 凡益之道，與時偕行。', '風雷，益﹔君子以見善則遷，有過則改。', '', '[{"p":1,"t":"yang","yc":"初九：利用為大作，元吉，無咎。","xt":"元吉無咎，下不厚事也。","jd":""},{"p":2,"t":"yin","yc":"六二：或益之，十朋之龜，弗克違，永貞吉。 王用享于帝，吉。","xt":"或益之，自外來也。","jd":""},{"p":3,"t":"yin","yc":"六三：益之用凶事，無咎。 有孚中行，告公用圭。","xt":"益用凶事，固有之也。","jd":""},{"p":4,"t":"yin","yc":"六四：中行告公從。 利用為依遷國。","xt":"告公從，以益志也。","jd":""},{"p":5,"t":"yang","yc":"九五：有孚惠心，勿問元吉。 有孚惠我德。","xt":"有孚惠心，勿問之矣。 惠我德，大得志也。","jd":""},{"p":6,"t":"yang","yc":"上九：莫益之，或擊之，立心勿恆，凶。","xt":"莫益之，偏辭也。 或擊之，自外來也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (43, '夬', 'Guài', '䷪', '兌/澤', '乾/天', '011111', '揚于王庭，孚號，有厲，告自邑，不利即戎，利有攸往。', '夬，決也，剛決柔也。健而說，決而和，揚于王庭，柔乘五剛也。孚號有厲，其危乃光也。 告自邑，不利即戎，所尚乃窮也。 利有攸往，剛長乃終也。', '澤上于天，夬﹔君子以施祿及下，居德則忌。', '', '[{"p":1,"t":"yang","yc":"初九：壯于前趾，往不勝為咎。","xt":"不勝而往，咎也。","jd":""},{"p":2,"t":"yang","yc":"九二：惕號，莫夜有戎，勿恤。","xt":"莫夜有戎，得中道也。","jd":""},{"p":3,"t":"yang","yc":"九三：壯于頄，有凶。 君子夬夬，獨行遇雨，若濡有慍，無咎。","xt":"君子夬夬，終無咎也。","jd":""},{"p":4,"t":"yang","yc":"九四：臀無膚，其行次且。 牽羊悔亡，聞言不信。","xt":"其行次且，位不當也。 聞言不信，聰不明也。","jd":""},{"p":5,"t":"yang","yc":"九五：莧陸夬夬，中行無咎。","xt":"中行無咎，中未光也。","jd":""},{"p":6,"t":"yin","yc":"上六：無號，終有凶。","xt":"無號之凶，終不可長也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (44, '姤', 'Gòu', '䷫', '乾/天', '巽/風', '111110', '姤 ：女壯，勿用取女。', '姤 ，遇也，柔遇剛也。勿用取女，不可與長也。 天地相遇，品物咸章也。 剛遇中正，天下大行也。 姤 之時義大矣哉！', '天下有風，姤 ﹔后以施命誥四方。', '', '[{"p":1,"t":"yin","yc":"初六：系于金柅，貞吉，有攸往，見凶，羸豕踟躅。","xt":"系于金柅，柔道牽也。","jd":""},{"p":2,"t":"yang","yc":"九二：包有魚，無咎，不利賓。","xt":"包有魚，義不及賓也。","jd":""},{"p":3,"t":"yang","yc":"九三：臀無膚，其行次且，厲，無大咎。","xt":"其行次且，行未牽也。","jd":""},{"p":4,"t":"yang","yc":"九四：包無魚，起凶。","xt":"無魚之凶，遠民也。","jd":""},{"p":5,"t":"yang","yc":"九五：以杞包瓜，含章，有隕自天。","xt":"九五含章，中正也。 有隕自天，志不舍命也。","jd":""},{"p":6,"t":"yang","yc":"上九：姤 其角，吝，無咎。","xt":"姤 其角，上窮吝也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (45, '萃', 'Cuì', '䷬', '兌/澤', '坤/地', '011000', '亨。 王假有廟，利見大人，亨，利貞。 用大牲吉，利有攸往。', '萃，聚也﹔順以說，剛中而應，故聚也。王假有廟，致孝享也。利見大人亨，聚以正也。 用大牲吉，利有攸往，順天命也。 觀其所聚，而天地萬物之情可見矣。', '澤上於地，萃﹔君子以除戎器，戒不虞。', '', '[{"p":1,"t":"yin","yc":"初六：有孚不終，乃亂乃萃，若號一握為笑，勿恤，往無咎。","xt":"乃亂乃萃，其志亂也。","jd":""},{"p":2,"t":"yin","yc":"六二：引吉，無咎，孚乃利用禴。","xt":"引吉無咎，中未變也。","jd":""},{"p":3,"t":"yin","yc":"六三：萃如，嗟如，無攸利，往無咎，小吝。","xt":"往無咎，上巽也。","jd":""},{"p":4,"t":"yang","yc":"九四：大吉，無咎。","xt":"大吉無咎，位不當也。","jd":""},{"p":5,"t":"yang","yc":"九五：萃有位，無咎。 匪孚，元永貞，悔亡。","xt":"萃有位，志未光也。","jd":""},{"p":6,"t":"yin","yc":"上六：齎咨涕洟，無咎。","xt":"齎咨涕洟，未安上也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (46, '升', 'Shēng', '䷭', '坤/地', '巽/風', '000110', '元亨，用見大人，勿恤，南征吉。', '柔以時升，巽而順，剛中而應，是以大亨。用見大人，勿恤﹔有慶也。 南征吉，志行也。', '地中生木，升﹔君子以順德，積小以高大。', '', '[{"p":1,"t":"yin","yc":"初六：允升，大吉。","xt":"允升大吉，上合志也。","jd":""},{"p":2,"t":"yang","yc":"九二：孚乃利用禴，無咎。","xt":"九二之孚，有喜也。","jd":""},{"p":3,"t":"yang","yc":"九三：升虛邑。","xt":"升虛邑，無所疑也。","jd":""},{"p":4,"t":"yin","yc":"六四：王用亨于岐山，吉無咎。","xt":"王用亨于岐山，順事也。","jd":""},{"p":5,"t":"yin","yc":"六五：貞吉，升階。","xt":"貞吉升階，大得志也。","jd":""},{"p":6,"t":"yin","yc":"上六：冥升，利于不息之貞。","xt":"冥升在上，消不富也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (47, '困', 'Kùn', '䷮', '兌/澤', '坎/水', '011010', '亨，貞，大人吉，無咎，有言不信。', '困，剛掩也。 險以說，困而不失其所，亨﹔其唯君子乎？ 貞大人吉，以剛中也。 有言不信，尚口乃窮也。', '澤無水，困﹔君子以致命遂志。', '', '[{"p":1,"t":"yin","yc":"初六：臀困于株木，入于幽谷，三歲不見。","xt":"入于幽谷，幽不明也。","jd":""},{"p":2,"t":"yang","yc":"九二：困于酒食，朱紱方來，利用亨祀，征凶，無咎。","xt":"困于酒食，中有慶也。","jd":""},{"p":3,"t":"yin","yc":"六三：困于石，據于蒺藜，入于其宮，不見其妻，凶。","xt":"據于蒺藜，乘剛也。 入于其宮，不見其妻，不祥也。","jd":""},{"p":4,"t":"yang","yc":"九四：來徐徐，困于金車，吝，有終。","xt":"來徐徐，志在下也。 雖不當位，有與也。","jd":""},{"p":5,"t":"yang","yc":"九五：劓刖，困于赤紱，乃徐有說，利用祭祀。","xt":"劓刖，志未得也。乃徐有說，以中直也。利用祭祀，受福也。","jd":""},{"p":6,"t":"yin","yc":"上六：困于葛藟，于臲卼，曰動悔。 有悔，征吉。","xt":"困于葛藟，未當也。 動悔，有悔吉，行也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (48, '井', 'Jǐng', '䷯', '坎/水', '巽/風', '010110', '改邑不改井，無喪無得，往來井井。汔至，亦未繘井，羸其瓶，凶。', '巽乎水而上水，井﹔井養而不窮也。改邑不改井，乃以剛中也。汔至亦未繘井，未有功也。 羸其瓶，是以凶也。', '木上有水，井﹔君子以勞民勸相。', '', '[{"p":1,"t":"yin","yc":"初六：井泥不食，舊井無禽。","xt":"井泥不食，下也。 舊井無禽，時舍也。","jd":""},{"p":2,"t":"yang","yc":"九二：井谷射鮒，瓮敝漏。","xt":"井谷射鮒，無與也。","jd":""},{"p":3,"t":"yang","yc":"九三：井渫不食，為我民惻，可用汲，王明，并受其福。","xt":"井渫不食，行惻也。 求王明，受福也。","jd":""},{"p":4,"t":"yin","yc":"六四：井甃，無咎。","xt":"井甃無咎，修井也。","jd":""},{"p":5,"t":"yang","yc":"九五：井冽，寒泉食。","xt":"寒泉之食，中正也。","jd":""},{"p":6,"t":"yin","yc":"上六：井收勿幕，有孚元吉。","xt":"元吉在上，大成也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (49, '革', 'Gé', '䷰', '兌/澤', '離/火', '011101', '己日乃孚，元亨利貞，悔亡。', '革，水火相息，二女同居，其志不相得，曰革。己日乃孚﹔革而信也。 文明以說，大亨以正，革而當，其悔乃亡。天地革而四時成，湯武革命，順乎天而應乎人，革之時義大矣哉！', '澤中有火，革﹔君子以治歷明時。', '', '[{"p":1,"t":"yang","yc":"初九：鞏用黃牛之革。","xt":"鞏用黃牛，不可以有為也。","jd":""},{"p":2,"t":"yin","yc":"六二：己日乃革之，征吉，無咎。","xt":"己日革之，行有嘉也。","jd":""},{"p":3,"t":"yang","yc":"九三：征凶，貞厲，革言三就，有孚。","xt":"革言三就，又何之矣。","jd":""},{"p":4,"t":"yang","yc":"九四：悔亡，有孚改命，吉。","xt":"改命之吉，信志也。","jd":""},{"p":5,"t":"yang","yc":"九五：大人虎變，未占有孚。","xt":"大人虎變，其文炳也。","jd":""},{"p":6,"t":"yin","yc":"上六：君子豹變，小人革面，征凶，居貞吉。","xt":"君子豹變，其文蔚也。 小人革面，順以從君也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (50, '鼎', 'Dǐng', '䷱', '離/火', '巽/風', '101110', '元吉，亨。', '鼎，象也。 以木巽火，亨飪也。 聖人亨以享上帝，而大亨以養聖賢。 巽而耳目聰明，柔進而上行，得中而應乎剛，是以元亨。', '木上有火，鼎﹔君子以正位凝命。', '', '[{"p":1,"t":"yin","yc":"初六：鼎顛趾，利出否，得妾以其子，無咎。","xt":"鼎顛趾，未悖也。 利出否，以從貴也。","jd":""},{"p":2,"t":"yang","yc":"九二：鼎有實，我仇有疾，不我能即，吉。","xt":"鼎有實，慎所之也。 我仇有疾，終無尤也。","jd":""},{"p":3,"t":"yang","yc":"九三：鼎耳革，其行塞，雉膏不食，方雨虧悔，終吉。","xt":"鼎耳革，失其義也。","jd":""},{"p":4,"t":"yang","yc":"九四：鼎折足，覆公餗，其形渥，凶。","xt":"覆公餗，信如何也。","jd":""},{"p":5,"t":"yin","yc":"六五：鼎黃耳金鉉，利貞。","xt":"鼎黃耳，中以為實也。","jd":""},{"p":6,"t":"yang","yc":"上九：鼎玉鉉，大吉，無不利。","xt":"玉鉉在上，剛柔節也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (51, '震', 'Zhèn', '䷲', '震/雷', '震/雷', '001001', '亨。 震來虩虩，笑言啞啞。 震驚百里，不喪匕鬯。', '震，亨。 震來虩虩，恐致福也。笑言啞啞，后有則也。 震驚百里，驚遠而懼邇也。 出可以守宗廟社稷，以為祭主也。', '洊雷，震﹔君子以恐懼修身。', '', '[{"p":1,"t":"yang","yc":"初九：震來虩虩，后笑言啞啞，吉。","xt":"震來虩虩，恐致福也。 笑言啞啞，后有則也。","jd":""},{"p":2,"t":"yin","yc":"六二：震來厲，億喪貝，躋于九陵，勿逐，七日得。","xt":"震來厲，乘剛也。","jd":""},{"p":3,"t":"yin","yc":"六三：震蘇蘇，震行無眚。","xt":"震蘇蘇，位不當也。","jd":""},{"p":4,"t":"yang","yc":"九四：震遂泥。","xt":"震遂泥，未光也。","jd":""},{"p":5,"t":"yin","yc":"六五：震往來厲，億無喪，有事。","xt":"震往來厲，危行也。 其事在中，大無喪也。","jd":""},{"p":6,"t":"yin","yc":"上六：震索索，視矍矍，征凶。 震不于其躬，于其鄰，無咎。 婚媾有言。","xt":"震索索，未得中也。 雖凶無咎，畏鄰戒也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (52, '艮', 'Gèn', '䷳', '艮/山', '艮/山', '100100', '艮其背，不獲其身，行其庭，不見其人，無咎。', '艮，止也。 時止則止，時行則行，動靜不失其時，其道光明。 艮其止，止其所也。 上下敵應，不相與也。 是以不獲其身，行其庭不見其人，無咎也。', '兼山，艮﹔君子以思不出其位。', '', '[{"p":1,"t":"yin","yc":"初六：艮其趾，無咎，利永貞。","xt":"艮其趾，未失正也。","jd":""},{"p":2,"t":"yin","yc":"六二：艮其腓，不拯其隨，其心不快。","xt":"不拯其隨，未退聽也。","jd":""},{"p":3,"t":"yang","yc":"九三：艮其限，列其夤，厲薰心。","xt":"艮其限，危薰心也。","jd":""},{"p":4,"t":"yin","yc":"六四：艮其身，無咎。","xt":"艮其身，止諸躬也。","jd":""},{"p":5,"t":"yin","yc":"六五：艮其輔，言有序，悔亡。","xt":"艮其輔，以中正也。","jd":""},{"p":6,"t":"yang","yc":"上九：敦艮，吉。","xt":"敦艮之吉，以厚終也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (53, '漸', 'Jiàn', '䷴', '巽/風', '艮/山', '110100', '女歸吉，利貞。', '漸之進也，女歸吉也。 進得位，往有功也。進以正，可以正邦也。其位剛，得中也。 止而巽，動不窮也。', '山上有木，漸﹔君子以居賢德，善俗。', '', '[{"p":1,"t":"yin","yc":"初六：鴻漸于干，小子厲，有言，無咎。","xt":"小子之厲，義無咎也。","jd":""},{"p":2,"t":"yin","yc":"六二：鴻漸于磐，飲食衎衎，吉。","xt":"飲食衎衎，不素飽也。","jd":""},{"p":3,"t":"yang","yc":"九三：鴻漸于陸，夫征不復，婦孕不育，凶﹔利御寇。","xt":"夫征不復，離群丑也。 婦孕不育，失其道也。利用御寇，順相保也。","jd":""},{"p":4,"t":"yin","yc":"六四：鴻漸于木，或得其桷，無咎。","xt":"或得其桷，順以巽也。","jd":""},{"p":5,"t":"yang","yc":"九五：鴻漸于陵，婦三歲不孕，終莫之勝，吉。","xt":"終莫之勝，吉﹔得所愿也。","jd":""},{"p":6,"t":"yang","yc":"上九：鴻漸于逵，其羽可用為儀，吉。","xt":"其羽可用為儀，吉﹔不可亂也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (54, '歸妹', 'Guī Mèi', '䷵', '震/雷', '兌/澤', '001011', '征凶，無攸利。', '歸妹，天地之大義也。天地不交，而萬物不興，歸妹人之終始也。說以動，所歸妹也。 征凶，位不當也。 無攸利，柔乘剛也。', '澤上有雷，歸妹﹔君子以永終知敝。', '', '[{"p":1,"t":"yang","yc":"初九：歸妹以娣，跛能履，征吉。","xt":"歸妹以娣，以恆也。 跛能履吉，相承也。","jd":""},{"p":2,"t":"yang","yc":"九二：眇能視，利幽人之貞。","xt":"利幽人之貞，未變常也。","jd":""},{"p":3,"t":"yin","yc":"六三：歸妹以須，反歸以娣。","xt":"歸妹以須，未當也。","jd":""},{"p":4,"t":"yang","yc":"九四：歸妹愆期，遲歸有時。","xt":"愆期之志，有待而行也。","jd":""},{"p":5,"t":"yin","yc":"六五：帝乙歸妹，其君之袂，不如其娣之袂良，月几望，吉。","xt":"帝乙歸妹，不如其娣之袂良也。 其位在中，以貴行也。","jd":""},{"p":6,"t":"yin","yc":"上六：女承筐無實，士刲羊無血，無攸利。","xt":"上六無實，承虛筐也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (55, '豐', 'Fēng', '䷶', '震/雷', '離/火', '001101', '亨，王假之，勿憂，宜日中。', '豐，大也。 明以動，故豐。王假之，尚大也。 勿憂宜日中，宜照天下也。日中則昃，月盈則食，天地盈虛，與時消息，而況人於人乎？況於鬼神乎？', '雷電皆至，豐﹔君子以折獄致刑。', '', '[{"p":1,"t":"yang","yc":"初九：遇其配主，雖旬無咎，往有尚。","xt":"雖旬無咎，過旬災也。","jd":""},{"p":2,"t":"yin","yc":"六二：豐其蔀，日中見斗，往得疑疾，有孚發若，吉。","xt":"有孚發若，信以發志也。","jd":""},{"p":3,"t":"yang","yc":"九三：豐其沛，日中見昧，折其右肱，無咎。","xt":"豐其沛，不可大事也。 折其右肱，終不可用也。","jd":""},{"p":4,"t":"yang","yc":"九四：豐其蔀，日中見斗，遇其夷主，吉。","xt":"豐其蔀，位不當也。 日中見斗，幽不明也。 遇其夷主，吉﹔行也。","jd":""},{"p":5,"t":"yin","yc":"六五：來章，有慶譽，吉。","xt":"六五之吉，有慶也。","jd":""},{"p":6,"t":"yin","yc":"上六：豐其屋，蔀其家，窺其戶，闃ㄑㄩˋ其無人，三歲不見，凶。","xt":"豐其屋，天際翔也。 窺其戶，闃其無人，自藏也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (56, '旅', 'Lǚ', '䷷', '離/火', '艮/山', '101100', '小亨，旅貞吉。', '旅，小亨，柔得中乎外，而順乎剛，止而麗乎明，是以小亨，旅貞吉也。 旅之時義大矣哉！', '山上有火，旅﹔君子以明慎用刑，而不留獄。', '', '[{"p":1,"t":"yin","yc":"初六：旅瑣瑣，斯其所取災。","xt":"旅瑣瑣，志窮災也。","jd":""},{"p":2,"t":"yin","yc":"六二：旅即次，懷其資，得童仆貞。","xt":"得童仆貞，終無尤也。","jd":""},{"p":3,"t":"yang","yc":"九三：旅焚其次，喪其童仆，貞厲。","xt":"旅焚其次，亦以傷矣。 以旅與下，其義喪也。","jd":""},{"p":4,"t":"yang","yc":"九四：旅于處，得其資斧，我心不快。","xt":"旅于處，未得位也。 得其資斧，心未快也。","jd":""},{"p":5,"t":"yin","yc":"六五：射雉一矢亡，終以譽命。","xt":"終以譽命，上逮也。","jd":""},{"p":6,"t":"yang","yc":"上九：鳥焚其巢，旅人先笑后號啕。 喪牛于易，凶。","xt":"以旅在上，其義焚也。 喪牛于易，終莫之聞也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (57, '巽', 'Xùn', '䷸', '巽/風', '巽/風', '110110', '小亨，利攸往，利見大人。', '重巽以申命，剛巽乎中正而志行。柔皆順乎剛，是以小亨，利有攸往，利見大人。', '隨風，巽﹔君子以申命行事。', '', '[{"p":1,"t":"yin","yc":"初六：進退，利武人之貞。","xt":"進退，志疑也。 利武人之貞，志治也。","jd":""},{"p":2,"t":"yang","yc":"九二：巽在床下，用史巫紛若，吉無咎。","xt":"紛若之吉，得中也。","jd":""},{"p":3,"t":"yang","yc":"九三：頻巽，吝。","xt":"頻巽之吝，志窮也。","jd":""},{"p":4,"t":"yin","yc":"六四：悔亡，田獲三品。","xt":"田獲三品，有功也。","jd":""},{"p":5,"t":"yang","yc":"九五：貞吉悔亡，無不利。 無初有終，先庚三日，后庚三日，吉。","xt":"九五之吉，位正中也。","jd":""},{"p":6,"t":"yang","yc":"上九：巽在床下，喪其資斧，貞凶。","xt":"巽在床下，上窮也。 喪其資斧，正乎凶也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (58, '兌', 'Duì', '䷹', '兌/澤', '兌/澤', '011011', '亨，利貞。', '兌，說也。 剛中而柔外，說以利貞，是以順乎天，而應乎人。 說以先民，民忘其勞﹔說以犯難，民忘其死﹔說之大，民勸矣哉！', '麗澤，兌﹔君子以朋友講習。', '', '[{"p":1,"t":"yang","yc":"初九：和兌，吉。","xt":"和兌之吉，行未疑也。","jd":""},{"p":2,"t":"yang","yc":"九二：孚兌，吉，悔亡。","xt":"孚兌之吉，信志也。","jd":""},{"p":3,"t":"yin","yc":"六三：來兌，凶。","xt":"來兌之凶，位不當也。","jd":""},{"p":4,"t":"yang","yc":"九四：商兌，未寧，介疾有喜。","xt":"九四之喜，有慶也。","jd":""},{"p":5,"t":"yang","yc":"九五：孚于剝，有厲。","xt":"孚于剝，位正當也。","jd":""},{"p":6,"t":"yin","yc":"上六：引兌。","xt":"上六引兌，未光也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (59, '渙', 'Huàn', '䷺', '巽/風', '坎/水', '110010', '亨。 王假有廟，利涉大川，利貞。', '渙，亨。 剛來而不窮，柔得位乎外而上同。 王假有廟，王乃在中也。 利涉大川，乘木有功也。', '風行水上，渙﹔先王以享于帝立廟。', '', '[{"p":1,"t":"yin","yc":"初六：用拯馬壯，吉。","xt":"初六之吉，順也。","jd":""},{"p":2,"t":"yang","yc":"九二：渙奔其機，悔亡。","xt":"渙奔其機，得愿也。","jd":""},{"p":3,"t":"yin","yc":"六三：渙其躬，無悔。","xt":"渙其躬，志在外也。","jd":""},{"p":4,"t":"yin","yc":"六四：渙其群，元吉。 渙有丘，匪夷所思。","xt":"渙其群，元吉﹔光大也。","jd":""},{"p":5,"t":"yang","yc":"九五：渙汗其大號，渙王居，無咎。","xt":"王居無咎，正位也。","jd":""},{"p":6,"t":"yang","yc":"上九：渙其血，去逖出，無咎。","xt":"渙其血，遠害也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (60, '節', 'Jié', '䷻', '坎/水', '兌/澤', '010011', '亨。 苦節不可貞。', '節，亨，剛柔分，而剛得中。苦節不可貞，其道窮也。說以行險，當位以節，中正以通。 天地節而四時成，節以制度，不傷財，不害民。', '澤上有水，節﹔君子以制數度，議德行。', '節。亨。苦節不可貞。
【白話】節卦。通達。苦澀的節制不能正固。
【解讀】• 節卦是下兌上坎，亦即“水澤節”。《序卦》說：“物不可以終離，故受之以節。”一直離散下去，並不適宜，所以接著要談節卦。節有節制、制止之意。《雜卦》說：“節，止也。”• 節卦與渙卦為正覆關係，所以論其來源，是由泰卦（䷊，第十一卦）變來，亦即泰卦九三與六五換位，形成節卦（䷻）。雖然卦辭說泰卦“吉亨”，但是若是保持不動，則依然天地無法交流。
勉強保持不動，就是“苦節”（“苦”有過度而苦之意），“不可貞”。由卦象看來，節卦下兌上坎是“澤上有水”，澤的容量有限，必須有所節制。
《彖》日：節，亨。剛柔分而剛得中。苦節不可貞，其道窮也。
說以行險，當位以節，中正以通。天地節而四時成。
節以制度，不傷財，不害民。
【白話】《彖傳》說：節卦，通達。剛強者與柔順者分開，並且剛強者取得中位。苦澀的節制不能正固，是因為路已經走到盡頭。喜悅而去冒險犯難，位置適當而能節制，居中守正才可通順。天地有節制，四季才會形成。用制度來節制，就不會浪費錢財，也不會禍害百姓。
【解讀】•  泰卦下乾上坤，陰陽二組力量壁壘分明，一變而為節卦，則陰爻陽爻得到交錯機會，並且九五與九二皆為陽爻，這就是“剛柔分而剛得中”。如果泰卦不變，則成為“苦節”，一切停滯下來，前無去路，所以說“不可貞”。
•  節卦下兌上坎，坎為險，兌為悅，亦即“說以行險”，意思是：節制並非完全避開挑戰，而是要在喜悅時才可冒險。得位時能夠節制，才可做到“中正以通”。就自然界而言，天地的運行有其節制，四季才會依序出現。就人間世而言，則須以制度來規範，才不至於耗費金錢與傷害百姓。
《象》日：澤上有水，節。君子以制數度，議德行。
【白話】《象傳》說：沼澤上有水，這就是節卦。君子由此領悟，要制定數量上的限度，評議道德上的行為表現。
【解讀】•  節卦是下兌上坎，坎為水，兌為澤，是為“澤上有水”。澤的容量是固定的，少則聚積，多則流瀉，顯示某種節制。
•  君子照顧百姓的生活所需，要“制數度”，並且為了提升社會風氣，要“議德行”。程頤說：“君子觀節之象，以制立數度，凡物之大小輕重高下文質，皆有數度；所以為節也，數多寡，度法制。議德行者，存諸中為德，發於外為行，人之德行，當義則中節。議謂適度求中節也。”《中庸》首章所推崇的中和，所強調的是：“喜怒哀樂之未發謂之中，發而皆中節謂之和。”', '[{"p":1,"t":"yang","yc":"初九：不出戶庭，無咎。","xt":"不出戶庭，知通塞也。","jd":"初九。不出戶庭，無咎。\n《象》曰：不出戶庭，知通塞也。\n【白話】初九。不離開門戶與庭院，沒有災難。\n《象傳》說：不離開門戶與庭院，是因為知道通達與閉塞。\n【解讀】• 在泰卦變為節卦的過程中，初九與其正應六四不受影響。現在處於節卦，理當有所節制，而初九知道自己的通（有正應）與塞（要收斂），所以“不出戶庭”。\n• 節卦出現互艮（六三、六四、九五），艮為門闕，又為止，初九距門闕還有兩步，所以要“不出戶庭”，如此能有分寸，可以“無咎”。\n•《繫辭上》談到這句爻辭，說：“子曰：‘亂之所生也，則言語以為階。君不密則失臣，臣不密則失身，幾事不密則害成，是以君子縝密而不出也。’”"},{"p":2,"t":"yang","yc":"九二：不出門庭，凶。","xt":"不出門庭，失時極也。","jd":"九二。不出門庭，兇。\n《象》曰：不出門庭兇，失時極也。\n【白話】九二。不走出門戶與庭院，有兇禍。\n《象傳》說：不走出門戶與庭院，會有兇禍，是因為過度錯過了時機。\n【解讀】• 九二與初九一樣，在節卦的互艮之下，但是九二自身已進人互震（九二、六三、六四）中，震為行，所以“不出門庭”反而是“兇”。\n• 九二以陽爻居下卦中位，在卦變過程中當行而未行，以致從原來的有應變成無應，甚至為六三所乘，所以說“失時極也”。“極”為過度，為極端，在本卦中則是錯失了節度。"},{"p":3,"t":"yin","yc":"六三：不節若，則嗟若，無咎。","xt":"不節之嗟，又誰咎也。","jd":"六三。不節若，則嗟若，無咎。\n《象》曰：不節之嗟，又誰咎也？【白話】六三。沒有節制的樣子，就會出現悲嘆的樣子，沒有責難。\n《象傳》說：沒有節制的悲嘆，又能責難誰呢？【解讀】• 泰卦六五居上卦之中，又有九二正應，現在成為節卦的六三，位置不中不正，又無正應，這都是“不節若”造成的。\n• 六三在下卦兌中，兌為口，所以說“則嗟若”。“無咎”的“咎”在此為責難、責怪的意思，這一切都是自己造成的，所以說“又誰咎也”。"},{"p":4,"t":"yin","yc":"六四：安節，亨。","xt":"安節之亨，承上道也。","jd":"六四。安節，亨。\n《象》日：安節之亨，承上道也。\n【白話】六四。安定的節制，通達。\n《象傳》說：安定的節制之所以通達，是因為順承上位者的正道。\n【解讀】• 六四在卦變時未動，卦變之後在互艮（六三、六四、九五）中，艮止，所以是“安節”。\n• 六四以陰爻居柔位，下有初九正應，現在又能順承居中守正的九五，亦即“承上道也”，所以說“亨”。"},{"p":5,"t":"yang","yc":"九五：甘節，吉﹔往有尚。","xt":"甘節之吉，居位中也。","jd":"九五。甘節，吉，往有尚。\n《象》曰：甘節之吉，居位中也。\n【白話】九五。甘美的節制，吉祥，前往受到推崇。\n《象傳》說：甘美的節制之所以吉祥，是因為處於中位。\n【解讀】• 九五在卦變時，由泰卦九三上來，取得泰卦上卦坤的中位；坤為土，依《尚書•洪範》所言，“土愛稼穡”，而“稼穡作甘”，所以九五是“甘節”。九五由下卦上來而取得尊位，是“往有尚”。\n• 九五之“吉”，在彖辭已經談到，就是“當位以節，中正以通”，總之則是“居位中也”。"},{"p":6,"t":"yin","yc":"上六：苦節，貞凶，悔亡。","xt":"苦節貞凶，其道窮也。","jd":"上六。苦節，貞兇，悔亡。\n《象》曰：苦節貞兇，其道窮也。\n【白話】上六。苦澀的節制，正固會有兇禍，懊惱消失。\n《象傳》說：苦澀的節制，正固會有兇禍，是因為路已經走到盡頭。\n【解讀】• 上六在泰卦中，原與九三正應，泰卦九三與六五換位形成節卦，使上六失去正應。上六現在處於上卦坎中，坎為險，為苦難，所以上六的節制是“苦節”。因為正固而陷人苦澀的處境，所以說“貞兇”。\n• 上六已至全卦終位，前無去路，“其道窮也”。不過，以陰爻居柔位，仍有柔順之德，可以隨從九五中位，而得以 “悔亡”。"}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (61, '中孚', 'Zhōng Fú', '䷼', '巽/風', '兌/澤', '110011', '豚魚吉，利涉大川，利貞。', '中孚，柔在內而剛得中。 說而巽，孚，乃化邦也。 豚魚吉，信及豚魚也。 利涉大川，乘木舟虛也。 中孚以利貞，乃應乎天也。', '澤上有風，中孚﹔君子以議獄緩死。', '中孚。豚魚，吉。利涉大川，利貞。
【白話】中孚卦。豬與魚出現，吉祥。適宜渡過大河，適宜正固。
【解讀】• 中孚卦是下兌上巽，亦即“風澤中孚”。《序卦》說：“節而信之，故受之以中孚。”有所節制，才可取信於人，所以接著要探討的是中孚卦。《雜卦》說：“中孚，信也。”符節在古代為信物，由卦象看，上下二卦搭配合宜，若合符節，可作為憑信。“中”指內心，所以“中孚”為內心誠信。
• 關於“豚魚”，程頤說：“豚躁魚冥，物之難感者也。孚信能感於豚魚，則無不至矣，所以吉也。”若由卦象找根據，則涉及兩度卦變，虞翻之說可供參考。他指出：“訟四之初也。”亦即訟卦（䷅，第六卦）的九四與初六換位而成中孚卦（ ䷼）。但是卦變多從十二訊息卦產生，所以他又說：“此當從四陽二陰之例，遁陰未及三，而大壯陽已至四，故從訟來。”結論則是要先由遁卦（䷠，第三十三卦）變為訟卦，再由訟卦變為中孚卦。他如此解釋的用意，是要找出“豚魚”的出處：遁卦有互巽（六二、九三、九四），巽為魚，而訟卦有下坎，坎為豕。遁變為訟，訟再變為中孚，所以說“豚魚，吉”。由此一例，可知歷代學者研究《易經》所費之心力。
• 中孚卦下兌上巽，巽為木，引申為木舟，兌為澤，木舟可行於澤上，所以說“利涉大川”。九五與九二皆為陽爻居中位，所以說“利貞”。
《彖》日：中孚，柔在內而剛得中。說而巽，孚乃化邦也。豚魚吉，信及豚魚也。利涉大川，乘木舟虛也。中孚以利貞，乃應乎天也。
【白話】《彖傳》說：中孚卦，柔順者在內而剛強者取得中位。喜悅而隨順，誠信才可感化邦國。豬與魚吉祥，是說誠信及於豬與魚。適宜渡過大河，是說乘坐木船還有空位。內心誠信而適宜正固，則是順應天之道。
【解讀】• 中孚卦是下兌上巽，卦象為上下四個陽爻居外，中間兩個陰爻，並且陽爻佔有五、二中位，亦即“柔在內而剛得中”。下兌為悅，上巽為隨順，有如百姓喜悅而君上隨順，誠信到這種地步，才可化民成俗，邦國大治。
• 程頤說：“內外皆實而中虛，為中孚之象。又二五皆陽，中實，亦為孚義。在二體則中實，在全體則中虛。中虛，信之本；中實，信之質。”講求誠信，必須態度謙虛，才可尊重別人；同時要腳踏實地，做到言出必行。
• “信及豚魚也”，表示精誠所至，金石為開，自然可以感動百姓。“乘木舟虛也”，則指涉全卦中間兩個陰爻，虛位以待。然後，能夠誠信而正固，就合乎天地運行的恆久法則了。
《象》曰：澤上有風，中孚。君子以議獄緩死。
【白話】《象傳》說：沼澤上有風在吹，這就是中孚卦。君子由此領悟，要認真討論訟案，緩慢判決死刑。
【解讀】• 中孚卦是下兌上巽，巽為風，兌為澤，所以說“澤上有風”。風有如政教命令，澤有如施恩於民 既要維持綱紀，又要照顧百姓。
• 君子所能做的是“議獄緩死”，在追求社會正義時，不忘同情體諒罪犯。', '[{"p":1,"t":"yang","yc":"初九：虞吉，有他不燕。","xt":"初九虞吉，志未變也。","jd":"初九。虞吉，有它不燕。\n《象》曰：初九虞吉，志未變也。\n【白話】初九。可預料就吉祥，有其他狀況則不安。\n《象傳》說：初九可預料就吉祥，是因為心意並未改變。\n【解讀】• “虞”為預料、猜測。古代有虞官，擔任王公貴族打獵時的嚮導。\n初九居中孚卦初位，上有六四正應，所作所為可以預料，猶如前有嚮導，不會迷路，所以“吉”。這也是初九“志未變也”的表現。\n• “燕”為安寧，“它”為其他。初九在下卦兌中，兌為澤，它又上臨互震（九二、六三、六四），震為雷，有雷入澤之象，應該沉寂安定，所以說“有它不燕”。"},{"p":2,"t":"yang","yc":"九二：鳴鶴在陰，其子和之，我有好爵，吾與爾靡之。","xt":"其子和之，中心愿也。","jd":"九二。鶴鳴在陰，其子和之。我有好爵，吾與爾靡之。\n《象》曰：其子和之，中心願也。\n【白話】九二。大鶴在樹蔭下啼叫，它的小鶴啼叫應和。我有美酒一罐，我要與你共享。\n《象傳》說：它的小鶴啼叫應和，是發自內心的願望。\n【解讀】• 九二以陽爻居中位，剛實居中，顯示誠信之至。自然界中，鶴在山林棲息，親子以鳴呼應，既屬本能之所為，也有全心的信賴。\n在人間世，朋友志同道合，願意分享一切。“爵”為酒杯，引申為酒。“靡”為共，引申共享。朋友共品美酒，貴在心意相通。\n•《繫辭上》引述孔子對這句爻辭的評述說：“君子居其室，出其言善，則千里之外應之，況其邇者乎？居其室，出其言不善，則千里之外違之，況其邇者乎？言出乎身，加乎民；行發乎邇，見乎遠。言行，君子之樞機。樞機之發，榮辱之主也。言行，君子之所以動天地也，可不慎乎？”"},{"p":3,"t":"yin","yc":"六三：得敵，或鼓或罷，或泣或歌。","xt":"可鼓或罷，位不當也。","jd":"六三。得敵，或鼓或罷，或泣或歌。\n《象》日：或鼓或罷，位不當也。\n【白話】六三。遇到對手，或擊鼓或休兵，或哭泣或唱歌。\n《象傳》說：或擊鼓或休兵，是因為位置不恰當。\n【解讀】• 六三在下卦終位，面臨上卦，可謂棋逢敵手。六三在互震（九二、六三、六四）中，震為雷，引申為擊鼓作戰；又在互艮（六三、六四、九五）中，艮為止，引申為休兵罷戰；六三在下卦兌中，兌為口，為悅，引申為唱歌；它又面臨上巽，巽為風，為號，引申為哭泣，於是形成爻辭的一段生動描寫。\n•六三之種種猶疑狀態，來自它的不中不正之位。"},{"p":4,"t":"yin","yc":"六四：月几望，馬匹亡，無咎。","xt":"馬匹亡，絕類上也。","jd":"六四。月既望，馬匹亡，無咎。\n《象》曰：馬匹亡，絕類上也。\n【白話】六四。月亮已經滿盈，馬匹丟失，沒有災難。\n《象傳》說：馬匹丟失，是因為離開同類往上走。\n【解讀】• “月既望”，王弼本作“月幾望”，而帛書本則作“月既望”。六四已到上卦巽，巽為農曆十六以後的月亮。如此取象系根據納甲之說：每月三日為震，八日為兌，十五日為乾（月盈），十六日為巽，二十三日為艮，三十日為坤（月虛），以此描寫月之盈虛。\n• 中孚卦由遁卦變來，遁卦上卦乾，乾為馬；現在六四進入上卦，使乾卦消失，所以說“馬匹亡”。\n• “月既望”與“馬匹亡”都不是美好的事，而六四可以“無咎”，原因在於六四自己陰爻居柔位，足以取信於人；並且離開原本在下卦的同類，往上順承九五之君。"},{"p":5,"t":"yang","yc":"九五：有孚攣如，無咎。","xt":"有孚攣如，位正當也。","jd":"九五。有孚攣如，無咎。\n《象》曰：有孚攣如，位正當也。\n【白話】九五。有誠信而繫念著，沒有災難。\n《象傳》說：有誠信而繫念著，是因為位置正確而恰當。\n【解讀】• 九五居中正之位，為全卦核心。“攣”為捲曲抽緊、繫念於心。\n九五在上卦巽中，巽為繩，又在互艮（六三、六四、九五）中，艮手，合之則為以手繫繩以連線各爻。\n• 九五的誠信不容置疑，但與九二不應，所以只可說是“無咎”。\n並且，真正的誠信不能全靠有形的力量來固結。"},{"p":6,"t":"yang","yc":"上九：翰音登于天，貞凶。","xt":"翰音登于天，何可長也。","jd":"上九。翰音登於天，貞兇。\n《象》曰：翰音登於天，何可長也？【白話】上九。雞啼的聲音傳升到天上，正固會有兇禍。\n《象傳》說：雞啼的聲音傳升到天上，怎麼可能長久？【解讀】•《禮記•曲禮下》：“凡祭宗廟之禮，牛曰一元大武.....雞曰翰音…”祭祀時特別稱雞為“翰音”，以示其音質之美，所以“翰音”為雞啼的聲音。上九在上卦巽中，巽為雞；它與六三正應，六三在下兌中，兌為口，合之則有雞鳴之象。\n• 上九位居全卦終位，又不懼聲名太大，而未覺察前無去路，“何可長也？”所以說“貞兇”。"}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (62, '小過', 'Xiǎo Guò', '䷽', '震/雷', '艮/山', '001100', '亨，利貞，可小事，不可大事。飛鳥遺之音，不宜上宜下，大吉。', '小過，小者過而亨也。 過以利貞，與時行也。 柔得中，是以小事吉也。 剛失位而不中，是以不可大事也。 有飛鳥之象焉，有飛鳥遺之音，不宜上宜下，大吉﹔上逆而下順也。', '山上有雷，小過﹔君子以行過乎恭，喪過乎哀，用過乎儉。', '', '[{"p":1,"t":"yin","yc":"初六：飛鳥以凶。","xt":"飛鳥以凶，不可如何也。","jd":""},{"p":2,"t":"yin","yc":"六二：過其祖，遇其妣﹔不及其君，遇其臣﹔無咎。","xt":"不及其君，臣不可過也。","jd":""},{"p":3,"t":"yang","yc":"九三：弗過防之，從或戕之，凶。","xt":"從或戕之，凶如何也。","jd":""},{"p":4,"t":"yang","yc":"九四：無咎，弗過遇之。 往厲必戒，勿用永貞。","xt":"弗過遇之，位不當也。 往厲必戒，終不可長也。","jd":""},{"p":5,"t":"yin","yc":"六五：密云不雨，自我西郊，公弋取彼在穴。","xt":"密云不雨，已上也。","jd":""},{"p":6,"t":"yin","yc":"上六：弗遇過之，飛鳥離之，凶，是謂災眚。","xt":"弗遇過之，已亢也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (63, '既濟', 'Jì Jì', '䷾', '坎/水', '離/火', '010101', '亨，小利貞，初吉終亂。', '既濟，亨，小者亨也。利貞，剛柔正而位當也。 初吉，柔得中也。終止則亂，其道窮也。', '水在火上，既濟﹔君子以思患而預防之。', '', '[{"p":1,"t":"yang","yc":"初九：曳其輪，濡其尾，無咎。","xt":"曳其輪， 義無咎也。","jd":""},{"p":2,"t":"yin","yc":"六二：婦喪其茀，勿逐，七日得。","xt":"七日得，以中道也。","jd":""},{"p":3,"t":"yang","yc":"九三：高宗伐鬼方，三年克之，小人勿用。","xt":"三年克之，憊也。","jd":""},{"p":4,"t":"yin","yc":"六四：儒有衣袽，終日戒。","xt":"終日戒，有所疑也。","jd":""},{"p":5,"t":"yang","yc":"九五：東鄰殺牛，不如西鄰之禴祭，實受其福。","xt":"東鄰殺牛，不如西鄰之時也﹔實受其福，吉大來也。","jd":""},{"p":6,"t":"yin","yc":"上六：濡其首，厲。","xt":"濡其首厲，何可久也。","jd":""}]');
INSERT INTO hexagrams (number, name_zh, name_en, symbol, upper_trigram, lower_trigram, binary_repr, gua_ci, tuan_zhuan, xiang_zhuan, description, yao) VALUES (64, '未濟', 'Wèi Jì', '䷿', '離/火', '坎/水', '101010', '亨，小狐汔濟，濡其尾，無攸利。', '未濟，亨﹔柔得中也。 小狐汔濟，未出中也。 濡其尾，無攸利﹔不續終也。 雖不當位，剛柔應也。', '火在水上，未濟﹔君子以慎辨物居方。', '', '[{"p":1,"t":"yin","yc":"初六：濡其尾，吝。","xt":"濡其尾，亦不知極也。","jd":""},{"p":2,"t":"yang","yc":"九二：曳其輪，貞吉。","xt":"九二貞吉，中以行正也。","jd":""},{"p":3,"t":"yin","yc":"六三：未濟，征凶，利涉大川。","xt":"未濟征凶，位不當也。","jd":""},{"p":4,"t":"yang","yc":"九四：貞吉，悔亡，震用伐鬼方，三年有賞于大國。","xt":"貞吉悔亡，志行也。","jd":""},{"p":5,"t":"yin","yc":"六五：貞吉，無悔，君子之光，有孚，吉。","xt":"君子之光，其暉吉也。","jd":""},{"p":6,"t":"yang","yc":"上九：有孚于飲酒，無咎，濡其首，有孚失是。","xt":"飲酒濡首，亦不知節也。","jd":""}]');
